import { useState, useMemo, useEffect } from "react";
import { SQL_Q } from "./data/sql_questions";
import { DSA_Q } from "./data/dsa_questions";
import { JAVA_Q } from "./data/java_questions";

/* ═══════════════════════════════════════════════════════════════
   COMPUTER NETWORKS — 150 Questions
═══════════════════════════════════════════════════════════════ */
const CN_Q = [
  { id: "cn1", diff: "easy", topic: "OSI Model", q: "How many layers does the OSI model have?", opts: ["5", "6", "7", "8"], ans: 2, exp: "The OSI model has exactly 7 layers: Physical, Data Link, Network, Transport, Session, Presentation, and Application — each with distinct responsibilities." },
  { id: "cn2", diff: "easy", topic: "OSI Model", q: "Which OSI layer is responsible for end-to-end communication and error recovery?", opts: ["Network Layer", "Transport Layer", "Session Layer", "Data Link Layer"], ans: 1, exp: "The Transport layer (Layer 4) ensures reliable, end-to-end delivery via error detection, retransmission, and flow control. TCP and UDP operate here." },
  { id: "cn3", diff: "easy", topic: "OSI Model", q: "At which OSI layer do routers primarily operate?", opts: ["Data Link (Layer 2)", "Network (Layer 3)", "Transport (Layer 4)", "Physical (Layer 1)"], ans: 1, exp: "Routers operate at Layer 3 (Network), reading IP headers to make forwarding decisions. They strip and rebuild Layer 2 frames at each hop." },
  { id: "cn4", diff: "easy", topic: "OSI Model", q: "Which layer converts data into bits for transmission over a physical medium?", opts: ["Data Link", "Presentation", "Physical", "Session"], ans: 2, exp: "The Physical layer (Layer 1) handles raw bit transmission — voltages, frequencies, cables, and connectors. It has no understanding of frames or packets." },
  { id: "cn5", diff: "easy", topic: "OSI Model", q: "Encryption and data compression are functions of which OSI layer?", opts: ["Session Layer", "Transport Layer", "Presentation Layer", "Application Layer"], ans: 2, exp: "The Presentation layer (Layer 6) handles data formatting, encryption, and compression so the receiving application can understand it regardless of platform." },
  { id: "cn6", diff: "easy", topic: "OSI Model", q: "What is the PDU at the Transport layer called?", opts: ["Frame", "Packet", "Segment", "Bit"], ans: 2, exp: "PDUs by layer — Physical: Bit, Data Link: Frame, Network: Packet, Transport: Segment, Application: Data." },
  { id: "cn7", diff: "easy", topic: "OSI Model", q: "Which OSI layer establishes, manages, and terminates sessions between applications?", opts: ["Transport", "Presentation", "Session", "Network"], ans: 2, exp: "The Session layer (Layer 5) manages dialogues — it sets up, coordinates, and terminates conversations between applications on different hosts." },
  { id: "cn8", diff: "easy", topic: "OSI Model", q: "Switches primarily operate at which OSI layer?", opts: ["Physical Layer", "Network Layer", "Data Link Layer", "Transport Layer"], ans: 2, exp: "Switches use MAC addresses at Layer 2 (Data Link) to make forwarding decisions. Layer 3 switches also perform routing." },
  { id: "cn9", diff: "easy", topic: "TCP/IP", q: "How many layers does the TCP/IP model have?", opts: ["4", "5", "6", "7"], ans: 0, exp: "TCP/IP has 4 layers: Network Access (Link), Internet, Transport, and Application. The Application layer maps to OSI's Session+Presentation+Application." },
  { id: "cn10", diff: "easy", topic: "TCP/IP", q: "Which protocol provides reliable, connection-oriented data delivery?", opts: ["UDP", "ICMP", "TCP", "ARP"], ans: 2, exp: "TCP is connection-oriented — it uses a 3-way handshake, sequence numbers, ACKs, and retransmissions to guarantee delivery." },
  { id: "cn11", diff: "easy", topic: "TCP/IP", q: "Which protocol is connectionless and provides no delivery guarantee?", opts: ["TCP", "UDP", "FTP", "SMTP"], ans: 1, exp: "UDP is connectionless with no handshake, ACKs, or retransmission — fast and ideal for real-time apps like DNS, VoIP, and video streaming." },
  { id: "cn12", diff: "easy", topic: "TCP/IP", q: "In the TCP three-way handshake, what is the correct sequence?", opts: ["SYN → ACK → SYN-ACK", "SYN → SYN-ACK → ACK", "ACK → SYN → SYN-ACK", "SYN-ACK → SYN → ACK"], ans: 1, exp: "Client sends SYN → Server replies SYN-ACK → Client confirms with ACK. Only after this full exchange is a reliable TCP connection established." },
  { id: "cn13", diff: "easy", topic: "TCP/IP", q: "Which field in the IP header identifies whether TCP or UDP is the payload?", opts: ["TTL", "Checksum", "Protocol", "Flags"], ans: 2, exp: "The Protocol field carries a number identifying the transport layer: 6 = TCP, 17 = UDP, 1 = ICMP." },
  { id: "cn14", diff: "easy", topic: "TCP/IP", q: "What does IP fragmentation accomplish?", opts: ["Encrypts packets", "Splits packets exceeding the MTU into smaller fragments", "Reassembles frames at the Data Link layer", "Routes packets faster"], ans: 1, exp: "When a packet's size exceeds the MTU (e.g., 1500 bytes on Ethernet), the IP layer fragments it. Fragments are reassembled only at the final destination." },
  { id: "cn15", diff: "easy", topic: "TCP/IP", q: "Which ICMP message is sent when a router cannot forward a packet?", opts: ["Echo Request", "Echo Reply", "Destination Unreachable", "Time Exceeded"], ans: 2, exp: "ICMP Destination Unreachable is sent by a router when it cannot deliver a packet — due to no route, blocked port, or host being down." },
  { id: "cn16", diff: "easy", topic: "Protocols", q: "What port does HTTP use by default?", opts: ["21", "23", "80", "443"], ans: 2, exp: "HTTP = port 80. HTTPS = 443. FTP = 21. Telnet = 23. SSH = 22. These port numbers are essential placement knowledge." },
  { id: "cn17", diff: "easy", topic: "Protocols", q: "What port does HTTPS use?", opts: ["80", "8080", "443", "22"], ans: 2, exp: "HTTPS uses port 443. It wraps HTTP inside a TLS tunnel, providing encryption, authentication, and integrity." },
  { id: "cn18", diff: "easy", topic: "Protocols", q: "Which protocol resolves IP addresses to MAC addresses?", opts: ["DNS", "RARP", "ARP", "DHCP"], ans: 2, exp: "ARP broadcasts 'Who has IP x.x.x.x?' on the local LAN. The owner replies with its MAC address, which is cached locally." },
  { id: "cn19", diff: "easy", topic: "Protocols", q: "Which protocol automatically assigns IP addresses to hosts?", opts: ["DNS", "ARP", "DHCP", "NAT"], ans: 2, exp: "DHCP uses a 4-step DORA process: Discover → Offer → Request → Acknowledge, assigning IPs from a pool." },
  { id: "cn20", diff: "easy", topic: "Protocols", q: "DNS resolves which of the following?", opts: ["IP address to MAC address", "MAC address to IP address", "Domain name to IP address", "IP address to Domain name"], ans: 2, exp: "DNS translates human-friendly domain names (www.google.com) into machine-routable IP addresses." },
  { id: "cn21", diff: "easy", topic: "Protocols", q: "Which protocol is used to SEND email?", opts: ["IMAP", "POP3", "SMTP", "FTP"], ans: 2, exp: "SMTP on port 25 (or 587 for submission) sends mail between servers and from clients to servers. IMAP/POP3 are for receiving." },
  { id: "cn22", diff: "easy", topic: "Protocols", q: "Which protocol is used to securely access a remote machine via CLI?", opts: ["Telnet", "FTP", "SSH", "SNMP"], ans: 2, exp: "SSH on port 22 encrypts the entire session. Telnet (port 23) sends everything in plaintext — a security risk." },
  { id: "cn23", diff: "easy", topic: "Protocols", q: "Ping uses which protocol internally?", opts: ["TCP", "UDP", "ICMP", "ARP"], ans: 2, exp: "Ping uses ICMP Echo Request (type 8) and Echo Reply (type 0). It measures round-trip time and packet loss." },
  { id: "cn24", diff: "easy", topic: "Protocols", q: "Which protocol is used for network management and monitoring of devices?", opts: ["SNMP", "SMTP", "SIP", "SOAP"], ans: 0, exp: "SNMP on UDP port 161 is used to monitor routers, switches, and servers. MIBs define the variables that can be queried." },
  { id: "cn25", diff: "easy", topic: "Protocols", q: "Which protocol retrieves email while keeping messages on the server?", opts: ["SMTP", "POP3", "IMAP", "FTP"], ans: 2, exp: "IMAP (port 143/993 with SSL) syncs email with the server — messages stay there. POP3 (port 110) downloads and typically deletes them." },
  { id: "cn26", diff: "easy", topic: "Protocols", q: "What does NAT stand for?", opts: ["Network Address Translation", "Network Access Terminal", "Node Address Table", "Network Aggregation Technique"], ans: 0, exp: "NAT allows multiple devices with private IPs (RFC 1918) to share one public IP by modifying IP/port headers in packets." },
  { id: "cn27", diff: "easy", topic: "Protocols", q: "FTP stands for?", opts: ["Fast Transfer Protocol", "File Transfer Protocol", "Frame Transfer Protocol", "Forwarding Transfer Protocol"], ans: 1, exp: "FTP uses TCP port 21 for control and port 20 for data. SFTP (over SSH) and FTPS (over TLS) are the secure alternatives." },
  { id: "cn28", diff: "easy", topic: "Protocols", q: "Which protocol synchronizes time across network devices?", opts: ["SNMP", "NTP", "LDAP", "RADIUS"], ans: 1, exp: "NTP (UDP port 123) synchronizes clocks. Accurate time is critical for log correlation, Kerberos authentication, and TLS certificate validation." },
  { id: "cn29", diff: "easy", topic: "Routing", q: "Which device connects multiple networks and forwards packets based on IP addresses?", opts: ["Hub", "Switch", "Router", "Bridge"], ans: 2, exp: "A router operates at Layer 3, reading IP headers to forward packets between networks. It maintains a routing table and supports protocols like OSPF, BGP, RIP." },
  { id: "cn30", diff: "easy", topic: "Routing", q: "What does TTL stand for in IP packets?", opts: ["Transfer Time Limit", "Time To Live", "Total Traffic Load", "Transmission Type Level"], ans: 1, exp: "TTL is decremented by 1 at each router hop. When it reaches 0, the packet is dropped and an ICMP Time Exceeded message is sent back — preventing infinite loops." },
  { id: "cn31", diff: "easy", topic: "Routing", q: "What is a default gateway?", opts: ["A server that assigns IPs", "The router IP used to reach external networks", "A firewall configuration", "A reserved IP for broadcast"], ans: 1, exp: "The default gateway is the next-hop router IP that a host uses for traffic destined outside its local subnet. Without it, hosts cannot communicate beyond their LAN." },
  { id: "cn32", diff: "easy", topic: "Routing", q: "What is a routing table used for?", opts: ["Store MAC addresses", "Store user passwords", "Determine the best path to forward packets", "Log all network traffic"], ans: 2, exp: "A routing table stores destination networks, next-hop addresses, and outgoing interfaces. Routers consult it for every packet, selecting the longest prefix match." },
  { id: "cn33", diff: "easy", topic: "Switching", q: "What is the main advantage of a switch over a hub?", opts: ["Switch is cheaper", "Switch broadcasts to all ports", "Switch forwards data only to the destination port", "Switch works at Layer 3"], ans: 2, exp: "A hub blindly broadcasts to all ports (creating collisions). A switch learns MAC addresses and forwards frames only to the correct port." },
  { id: "cn34", diff: "easy", topic: "Switching", q: "What is a VLAN?", opts: ["A type of physical cable", "A virtual private network", "A logical grouping of devices regardless of physical location", "A routing protocol"], ans: 2, exp: "A VLAN segments a physical switch into multiple logical networks, reducing broadcast domains, improving security, and enabling traffic isolation." },
  { id: "cn35", diff: "easy", topic: "Switching", q: "What does CSMA/CD stand for?", opts: ["Carrier Sense Multiple Access / Collision Detection", "Carrier Signal Multiple Access / Collision Delay", "Channel Sense Multiple Access / Collision Detection", "Carrier Sense Media Access / Carrier Detection"], ans: 0, exp: "CSMA/CD is Ethernet's collision handling: sense the carrier before sending; if a collision is detected, stop, wait a random backoff, then retry." },
  { id: "cn36", diff: "easy", topic: "Subnetting", q: "What is the default subnet mask for a Class C IP address?", opts: ["255.0.0.0", "255.255.0.0", "255.255.255.0", "255.255.255.255"], ans: 2, exp: "Class C: /24 = 255.255.255.0, supporting 254 usable hosts. Class B: /16 = 255.255.0.0. Class A: /8 = 255.0.0.0." },
  { id: "cn37", diff: "easy", topic: "Subnetting", q: "How many bits are in an IPv4 address?", opts: ["16", "32", "64", "128"], ans: 1, exp: "IPv4 = 32 bits, written as 4 octets in dotted decimal (e.g., 192.168.1.1). IPv6 = 128 bits, written in hexadecimal groups." },
  { id: "cn38", diff: "easy", topic: "Subnetting", q: "How many bits are in an IPv6 address?", opts: ["32", "64", "128", "256"], ans: 2, exp: "IPv6 = 128 bits, written as 8 groups of 4 hex digits separated by colons. It provides 2^128 addresses." },
  { id: "cn39", diff: "easy", topic: "Subnetting", q: "What is the broadcast address for the subnet 192.168.1.0/24?", opts: ["192.168.1.0", "192.168.1.1", "192.168.1.254", "192.168.1.255"], ans: 3, exp: "In a /24: .0 = network address, .255 = broadcast (sent to all hosts). Usable range: .1 to .254 = 254 hosts." },
  { id: "cn40", diff: "easy", topic: "Subnetting", q: "Which IP address range is reserved for loopback testing?", opts: ["10.0.0.0/8", "127.0.0.0/8", "192.168.0.0/16", "172.16.0.0/12"], ans: 1, exp: "127.0.0.0/8 is the loopback range. 127.0.0.1 ('localhost') tests the host's own TCP/IP stack without sending traffic." },
  { id: "cn41", diff: "easy", topic: "Subnetting", q: "A Class A IP address has how many bits for the host portion by default?", opts: ["8", "16", "24", "28"], ans: 2, exp: "Class A: 8 network bits + 24 host bits = 2^24 - 2 = 16,777,214 usable hosts per network." },
  { id: "cn42", diff: "easy", topic: "Data Link", q: "What is the purpose of a MAC address?", opts: ["Identify a network globally", "Identify a device on the internet", "Identify a device on a local network segment", "Assign IP addresses dynamically"], ans: 2, exp: "MAC addresses are 48-bit hardware addresses that uniquely identify devices on a local network segment. They operate at Layer 2 and are not routable." },
  { id: "cn43", diff: "easy", topic: "Data Link", q: "What is the size of a MAC address?", opts: ["32 bits", "48 bits", "64 bits", "128 bits"], ans: 1, exp: "MAC addresses are 48 bits (6 bytes), written as XX:XX:XX:XX:XX:XX in hex. The first 3 bytes = OUI (manufacturer), last 3 = device-specific." },
  { id: "cn44", diff: "easy", topic: "Data Link", q: "What does 802.11 refer to?", opts: ["Ethernet standard", "Wi-Fi (wireless LAN) standard", "Bluetooth standard", "Token Ring standard"], ans: 1, exp: "IEEE 802.11 defines Wi-Fi standards: 802.11a/b/g/n/ac/ax (Wi-Fi 6)/be (Wi-Fi 7). 802.3 = Ethernet, 802.1Q = VLAN tagging." },
  { id: "cn45", diff: "easy", topic: "Security", q: "What does a firewall primarily do?", opts: ["Speeds up network traffic", "Assigns IP addresses to hosts", "Filters incoming and outgoing traffic based on security rules", "Converts domain names to IP addresses"], ans: 2, exp: "A firewall enforces a security policy by permitting or blocking traffic based on rules (IP, port, protocol, state)." },
  { id: "cn46", diff: "easy", topic: "Security", q: "What is the purpose of SSL/TLS?", opts: ["Assign IP addresses", "Encrypt data in transit between client and server", "Filter network packets", "Compress data for faster transmission"], ans: 1, exp: "TLS provides encryption (confidentiality), authentication (server identity via certificates), and integrity (MAC). It replaced the deprecated SSL." },
  { id: "cn47", diff: "easy", topic: "Security", q: "What type of encryption uses one shared key for both encryption and decryption?", opts: ["Asymmetric encryption", "Symmetric encryption", "Hashing", "Public key cryptography"], ans: 1, exp: "Symmetric encryption (e.g., AES-256) uses one shared key — very fast for bulk data but requires secure key exchange." },
  { id: "cn48", diff: "easy", topic: "App Layer", q: "Which protocol does a web browser use to fetch web pages?", opts: ["FTP", "SMTP", "HTTP or HTTPS", "DNS"], ans: 2, exp: "Browsers use HTTP (port 80) for plain text and HTTPS (port 443, HTTP over TLS) for encrypted web traffic." },
  { id: "cn49", diff: "easy", topic: "App Layer", q: "What is traceroute used for?", opts: ["Test DNS resolution", "Map the route packets take to a destination, showing each hop", "Test firewall rules", "Measure download speed"], ans: 1, exp: "Traceroute sends packets with incrementing TTL values. Each router that decrements TTL to 0 sends back an ICMP Time Exceeded, revealing its IP and RTT." },
  { id: "cn50", diff: "easy", topic: "App Layer", q: "Which OSI layers does the TCP/IP Application layer combine?", opts: ["Only Application (Layer 7)", "Application and Transport", "Session (5), Presentation (6), and Application (7)", "Network and Transport"], ans: 2, exp: "TCP/IP's Application layer is a superset of OSI's top three layers: Session (5), Presentation (6), and Application (7)." },
  { id: "cn51", diff: "medium", topic: "Subnetting", q: "You have 192.168.10.0/28. How many usable host addresses are available?", opts: ["14", "16", "30", "254"], ans: 0, exp: "/28 means 4 host bits → 2⁴ = 16 total addresses. Subtract 2 (network address + broadcast) = 14 usable host addresses." },
  { id: "cn52", diff: "medium", topic: "Subnetting", q: "A company needs 5 subnets each supporting at least 25 hosts from 192.168.1.0/24. Most efficient mask?", opts: ["/25 (126 hosts)", "/26 (62 hosts)", "/27 (30 hosts)", "/28 (14 hosts)"], ans: 2, exp: "/27 gives 32 addresses per subnet (30 usable) — sufficient for 25 hosts. You get 8 such subnets from a /24." },
  { id: "cn53", diff: "medium", topic: "Subnetting", q: "How many /26 subnets can be created from a /24 network?", opts: ["2", "4", "8", "16"], ans: 1, exp: "/26 borrows 2 bits from /24: 2² = 4 subnets. Each /26 has 64 addresses (62 usable)." },
  { id: "cn54", diff: "medium", topic: "Subnetting", q: "What is VLSM and what problem does it solve?", opts: ["Variable Length Security Mask", "Variable Length Subnet Masking — allows subnets of different sizes, reducing IP waste", "Virtual LAN Security Model", "Variable Latency Speed Measurement"], ans: 1, exp: "VLSM lets you carve subnets of different sizes from one block — /30 for point-to-point links, /24 for large LANs. Prevents address waste." },
  { id: "cn55", diff: "medium", topic: "Subnetting", q: "What is CIDR and why was it introduced?", opts: ["A routing protocol to replace OSPF", "Classless Inter-Domain Routing — flexible prefix lengths to slow IPv4 exhaustion and enable route aggregation", "A protocol for dynamic IP assignment", "A security standard for routers"], ans: 1, exp: "CIDR (RFC 1519) abolished the rigid Class A/B/C system, allowing any prefix length. This enabled route aggregation, shrinking routing tables and conserving IPv4 space." },
  { id: "cn56", diff: "medium", topic: "Subnetting", q: "Which subnet mask minimizes IP waste on a point-to-point WAN link?", opts: ["/28 (14 usable)", "/29 (6 usable)", "/30 (2 usable)", "/31 or /30 depending on RFC support"], ans: 3, exp: "/30 gives exactly 2 usable hosts. RFC 3021 allows /31 (treating both as host addresses), which is even more efficient for point-to-point." },
  { id: "cn57", diff: "medium", topic: "Routing", q: "What is the key difference between static and dynamic routing?", opts: ["Static is always faster than dynamic", "Static routes are manually configured; dynamic routes are learned automatically via protocols like OSPF or BGP", "Static routing uses more bandwidth", "Dynamic routing always requires more CPU"], ans: 1, exp: "Static routes: manually entered, no overhead, no adaptability. Dynamic routing (OSPF, BGP, RIP) automatically discovers and adapts to topology changes." },
  { id: "cn58", diff: "medium", topic: "Routing", q: "RIP uses which metric to determine the best path?", opts: ["Bandwidth", "Hop count", "Delay", "Cost (inverse bandwidth)"], ans: 1, exp: "RIP uses hop count (max 15; 16 = infinite/unreachable). Its simplicity is also its weakness — it may choose a slower, lower-hop path over a faster, higher-hop one." },
  { id: "cn59", diff: "medium", topic: "Routing", q: "OSPF is classified as which type of routing protocol?", opts: ["Distance vector", "Link state", "Path vector", "Hybrid (advanced distance vector)"], ans: 1, exp: "OSPF is a link-state protocol. Every router floods LSAs, builds an identical LSDB, and runs Dijkstra's SPF algorithm to compute the shortest path tree." },
  { id: "cn60", diff: "medium", topic: "Routing", q: "BGP is primarily used for which purpose?", opts: ["Routing within a company LAN", "Routing between autonomous systems (ASes) on the internet", "Dynamically assigning IP addresses", "Encrypting routing update information"], ans: 1, exp: "BGP is the internet's routing protocol, exchanging reachability between ASes. It is a path-vector protocol, using AS_PATH to prevent loops." },
  { id: "cn61", diff: "medium", topic: "Routing", q: "What problem does split horizon solve in distance-vector routing?", opts: ["Routing loops between neighbors", "High CPU usage on routers", "Slow convergence only", "Packet fragmentation"], ans: 0, exp: "Split horizon: never advertise a route back out the interface you learned it from. This prevents the most common two-node routing loop." },
  { id: "cn62", diff: "medium", topic: "Routing", q: "A packet for 10.1.5.0/24 arrives at a router with routes 10.0.0.0/8 and 10.1.0.0/16. Which is chosen?", opts: ["10.0.0.0/8 — more general", "10.1.0.0/16 — longest prefix match", "Both are used via load balancing", "The packet is dropped"], ans: 1, exp: "Longest Prefix Match (LPM): the most specific matching route wins. /16 is more specific than /8." },
  { id: "cn63", diff: "medium", topic: "Routing", q: "What is administrative distance (AD) in routing?", opts: ["The physical cable distance between two routers", "A value ranking the trustworthiness of different routing sources", "The maximum hop count permitted", "The available bandwidth on a link"], ans: 1, exp: "AD is used when multiple protocols advertise a route to the same destination. Lower AD = more trusted. Connected=0, Static=1, EIGRP=90, OSPF=110, RIP=120." },
  { id: "cn64", diff: "medium", topic: "Routing", q: "What is route summarization (aggregation)?", opts: ["Splitting one network into many smaller subnets", "Combining multiple specific routes into a single summarized advertisement", "Encrypting routing protocol updates", "Prioritizing certain routes over others"], ans: 1, exp: "Route summarization (e.g., advertising 192.168.0.0/22 instead of four /24s) reduces routing table size, decreases update traffic, and hides internal topology." },
  { id: "cn65", diff: "medium", topic: "Routing", q: "EIGRP uses which combination of metrics?", opts: ["Hop count only", "Bandwidth and delay (primarily), plus optional load and reliability", "Cost based on interface speed only", "Hop count and reliability combined"], ans: 1, exp: "EIGRP's composite metric = K1×bandwidth + K3×delay (by default). It uses the DUAL algorithm, guaranteeing loop-free paths." },
  { id: "cn66", diff: "medium", topic: "Routing", q: "What is a null/blackhole route and when is it used?", opts: ["A backup route activated when the primary fails", "Discards packets for a specific prefix — used to prevent routing loops with summary routes or block traffic", "Routes packets through a VPN tunnel", "A static route with the highest possible metric"], ans: 1, exp: "A null route (e.g., 'ip route 10.0.0.0 255.0.0.0 Null0') discards matching packets. Used with route summarization to prevent loops." },
  { id: "cn67", diff: "medium", topic: "Switching", q: "What is the purpose of Spanning Tree Protocol (STP)?", opts: ["Assign IP addresses to switches automatically", "Prevent broadcast storms by eliminating Layer 2 forwarding loops", "Encrypt traffic between VLANs on trunk links", "Balance traffic load across multiple uplinks simultaneously"], ans: 1, exp: "Without STP, redundant switch paths would cause broadcast frames to loop endlessly (broadcast storm). STP elects a Root Bridge and blocks redundant ports." },
  { id: "cn68", diff: "medium", topic: "Switching", q: "In STP, what determines the Root Bridge election?", opts: ["The switch with the highest MAC address", "The switch with the lowest Bridge ID (Priority + MAC address)", "The switch closest to the internet gateway", "The switch with the most active ports"], ans: 1, exp: "Root Bridge = lowest Bridge Priority (default 32768) + MAC as tiebreaker. Manually set a lower priority (e.g., 4096) on the intended root." },
  { id: "cn69", diff: "medium", topic: "Switching", q: "What is MAC flooding and what vulnerability does it exploit?", opts: ["Flooding MAC address updates to all connected VLANs", "Overflowing the switch's CAM table with fake MACs, causing it to broadcast all traffic like a hub", "Sending oversized frames to cause a switch buffer overflow", "Spoofing multiple MAC addresses to monopolize switch bandwidth"], ans: 1, exp: "Switch CAM tables have finite size. MAC flooding fills it with fake entries, forcing the switch into fail-open mode (broadcasts everything). Port Security mitigates it." },
  { id: "cn70", diff: "medium", topic: "Switching", q: "What is the difference between an access port and a trunk port?", opts: ["Access ports carry multiple VLANs; trunk ports carry a single VLAN", "Access ports carry traffic for one VLAN; trunk ports carry multiple VLANs using 802.1Q tagging", "Access ports connect to routers; trunk ports connect to end devices", "Trunk ports are simply faster versions of access ports"], ans: 1, exp: "Access ports connect end devices to a single VLAN (untagged traffic). Trunk ports connect switches/routers and carry multiple VLANs using 802.1Q 4-byte tags." },
  { id: "cn71", diff: "medium", topic: "Switching", q: "What is proxy ARP and when is it useful?", opts: ["ARP that hides the real MAC address for security", "A router replies to ARP requests for remote hosts with its own MAC, enabling hosts without a default gateway to reach other subnets", "A broadcast ARP sent simultaneously to all subnets", "ARP used exclusively in wireless networks"], ans: 1, exp: "With Proxy ARP, a router responds to ARP for IPs it can reach, substituting its own MAC. Useful for hosts misconfigured without a gateway." },
  { id: "cn72", diff: "medium", topic: "Switching", q: "What is BPDU Guard and why is it configured on access ports?", opts: ["Speeds up STP convergence on trunk links", "Shuts down a port immediately if a BPDU is received — preventing rogue switches from altering the STP topology", "Prevents CAM table flooding on access ports", "A VLAN security mechanism for tagging frames"], ans: 1, exp: "PortFast + BPDU Guard: PortFast skips STP listening/learning states. If a BPDU is then received, BPDU Guard puts the port in err-disabled immediately." },
  { id: "cn73", diff: "medium", topic: "Protocols", q: "Which DNS record type maps a domain name to an IPv4 address?", opts: ["MX record", "CNAME record", "A record", "AAAA record"], ans: 2, exp: "A record = domain → IPv4. AAAA = domain → IPv6. MX = mail server. CNAME = alias pointing to another domain. NS = authoritative name servers." },
  { id: "cn74", diff: "medium", topic: "Protocols", q: "Which transport protocol do DNS queries typically use and why?", opts: ["TCP — for guaranteed delivery", "UDP — for low overhead and fast responses", "TCP — because DNS records are large", "Both TCP and UDP always used simultaneously"], ans: 1, exp: "DNS uses UDP port 53 for queries (fast, low overhead). TCP port 53 is used for zone transfers (AXFR) and responses exceeding 512 bytes (or 4096 with EDNS0)." },
  { id: "cn75", diff: "medium", topic: "Protocols", q: "What is the role of RADIUS in a network?", opts: ["Resolve DNS queries for network devices", "Provide centralized Authentication, Authorization, and Accounting (AAA)", "Translate private IP addresses to public ones", "Monitor and measure available bandwidth"], ans: 1, exp: "RADIUS (UDP 1812/1813) provides centralized AAA for network access. Used with 802.1X for Wi-Fi/wired authentication and VPN access." },
  { id: "cn76", diff: "medium", topic: "Protocols", q: "What is the purpose of DSCP (Differentiated Services Code Point) in the IP header?", opts: ["Identify the encapsulated transport protocol", "Mark packets with QoS class information so routers can prioritize traffic", "Fragment large packets before routing", "Detect and report routing loops to the sender"], ans: 1, exp: "DSCP (6 bits in the IP ToS field) marks packets with traffic class (e.g., EF for VoIP, AF41 for video). QoS-enabled routers use this to prioritize traffic." },
  { id: "cn77", diff: "medium", topic: "Protocols", q: "What protocol does VoIP primarily use for call signaling?", opts: ["HTTP", "SIP (Session Initiation Protocol)", "SMTP", "FTP"], ans: 1, exp: "SIP handles VoIP signaling — setting up, modifying, and terminating calls. RTP (Real-time Transport Protocol) carries the actual audio/video media stream." },
  { id: "cn78", diff: "medium", topic: "Protocols", q: "A web application uses WebSockets. What distinguishes them from HTTP?", opts: ["WebSockets use UDP for faster delivery", "WebSockets maintain a persistent full-duplex connection after an initial HTTP upgrade handshake", "WebSockets automatically encrypt all data by default", "WebSockets cannot be used over HTTPS connections"], ans: 1, exp: "WebSockets start with an HTTP 101 Upgrade request. Once upgraded, a persistent full-duplex TCP channel is open — both sides can send data anytime." },
  { id: "cn79", diff: "medium", topic: "Congestion", q: "Which TCP mechanism prevents overwhelming the network during connection startup?", opts: ["Fast Retransmit", "Slow Start", "Receiver-side Flow Control", "Sliding Window Protocol"], ans: 1, exp: "Slow Start begins with cwnd=1 MSS, doubling each RTT until ssthresh is reached, then switching to Congestion Avoidance (linear growth). It probes capacity cautiously." },
  { id: "cn80", diff: "medium", topic: "Congestion", q: "What happens to the TCP congestion window when triple duplicate ACKs are detected?", opts: ["cwnd is set to 0 and connection resets", "ssthresh = cwnd/2 and cwnd = ssthresh (Fast Recovery — not full Slow Start)", "cwnd is immediately reset to 1 MSS", "cwnd doubles to recover lost throughput"], ans: 1, exp: "Triple dup ACKs signal a single loss. Fast Retransmit resends the segment; Fast Recovery sets ssthresh=cwnd/2 and cwnd=ssthresh — avoiding expensive full Slow Start restart." },
  { id: "cn81", diff: "medium", topic: "Congestion", q: "What is the significance of ssthresh (slow start threshold) in TCP?", opts: ["It represents the maximum allowed window size", "It marks where TCP transitions from exponential (Slow Start) to linear (Congestion Avoidance) growth", "It defines the minimum RTT before backoff begins", "It equals the receiver's advertised buffer size"], ans: 1, exp: "Below ssthresh: cwnd doubles each RTT (Slow Start). At ssthresh: cwnd grows by 1 MSS per RTT (Congestion Avoidance)." },
  { id: "cn82", diff: "medium", topic: "Congestion", q: "What is ECN (Explicit Congestion Notification) and how does it improve on packet drops?", opts: ["A routing protocol that reroutes around congested links", "Routers mark packets (CE bit) instead of dropping them to signal congestion; the receiver echoes this to the sender to reduce rate without loss", "ECN increases the sender's cwnd when congestion is detected", "ECN is a firewall mechanism that rate-limits specific traffic flows"], ans: 1, exp: "Traditional congestion is signaled by packet drops. ECN sets the CE bit in the IP header; the receiver echoes it via TCP's ECE/CWR flags; the sender backs off without a retransmission event." },
  { id: "cn83", diff: "medium", topic: "Congestion", q: "What is the primary difference between flow control and congestion control in TCP?", opts: ["They are the same mechanism with different names", "Flow control prevents overwhelming the receiver (using receiver window); congestion control prevents overwhelming the network (using cwnd)", "Congestion control operates at Layer 2; flow control at Layer 4", "Flow control only works with UDP; congestion control is TCP-specific"], ans: 1, exp: "Flow control: receiver advertises its buffer size (rwnd); sender respects it. Congestion control: sender estimates network capacity via cwnd. Effective send rate = min(cwnd, rwnd)." },
  { id: "cn84", diff: "medium", topic: "Congestion", q: "UDP does not perform congestion control. What problem can this cause?", opts: ["Slower transmission speeds for UDP applications", "UDP traffic can congest shared links, starving TCP flows that do back off", "IPv4 addresses get exhausted more quickly", "Routing loops occur between UDP-heavy routers"], ans: 1, exp: "TCP backs off when it detects congestion. UDP doesn't. Heavy UDP traffic can fill buffers, causing TCP flows to throttle while UDP streams continue unabated — unfair bandwidth sharing." },
  { id: "cn85", diff: "medium", topic: "Security", q: "What type of attack floods a server with SYN requests without completing the handshake?", opts: ["Smurf Attack (ICMP amplification)", "SYN Flood DoS attack", "Man-in-the-Middle attack", "Session Replay attack"], ans: 1, exp: "A SYN Flood sends thousands of SYN packets (often spoofed IPs) but never sends the final ACK. The server allocates resources for each half-open connection until the table is exhausted." },
  { id: "cn86", diff: "medium", topic: "Security", q: "What is ARP poisoning / ARP spoofing?", opts: ["Sending malformed ARP packets to crash a switch", "Sending gratuitous ARP replies to associate the attacker's MAC with a legitimate IP, enabling a Man-in-the-Middle attack", "Flooding the network with excessive ARP broadcast requests", "Blocking all ARP responses on a subnet"], ans: 1, exp: "ARP spoofing sends unsolicited ARP replies, poisoning the victim's ARP cache. Traffic intended for the gateway flows through the attacker instead — enabling MITM, sniffing, or modification." },
  { id: "cn87", diff: "medium", topic: "Security", q: "Which type of firewall maintains state information about active connections?", opts: ["Simple packet filter (stateless)", "Stateless firewall — inspects each packet independently", "Stateful inspection firewall — tracks connection state", "Application gateway — operates at Layer 7 only"], ans: 2, exp: "A stateful firewall tracks connection state (SYN sent, established, FIN). It only allows return traffic for established sessions." },
  { id: "cn88", diff: "medium", topic: "Security", q: "What is the purpose of DNSSEC?", opts: ["Encrypt DNS query content to prevent eavesdropping", "Add digital signatures to DNS records, allowing resolvers to verify authenticity and prevent cache poisoning", "Speed up DNS resolution by caching more aggressively", "Assign DNS records to IP addresses dynamically"], ans: 1, exp: "DNSSEC uses public-key cryptography to sign DNS records (RRSIG). Resolvers validate signatures from the chain of trust rooted at the root zone, preventing Kaminsky-style cache poisoning." },
  { id: "cn89", diff: "medium", topic: "Security", q: "What is a DMZ in network security architecture?", opts: ["A private subnet reserved exclusively for internal database servers", "A perimeter network segment hosting public-facing services, isolated from the internal network by firewalls", "A type of encrypted VPN tunnel for remote workers", "A firewall bypass mechanism for trusted external partners"], ans: 1, exp: "A DMZ sits between two firewalls: one faces the internet, one faces the internal network. Web, mail, and DNS servers go here. If compromised, the internal network is still protected." },
  { id: "cn90", diff: "medium", topic: "Security", q: "What is Perfect Forward Secrecy (PFS) in TLS?", opts: ["Encryption that persists after the TLS session has ended", "Ephemeral key exchange (ECDHE/DHE) ensuring past sessions cannot be decrypted even if the server's long-term private key is later compromised", "A mechanism that prevents session replay attacks", "A certificate pinning technique to prevent rogue CA attacks"], ans: 1, exp: "Without PFS, an attacker recording TLS traffic can later decrypt it if they steal the server's private key. PFS uses ephemeral key exchange — session keys are generated fresh each time and discarded." },
  { id: "cn91", diff: "medium", topic: "Security", q: "What is a replay attack?", opts: ["Intercepting and modifying data packets in transit", "Capturing a valid authentication sequence and retransmitting it later to gain unauthorized access", "Flooding a network with traffic to exhaust resources", "Exploiting SQL injection vulnerabilities in a web application"], ans: 1, exp: "In a replay attack, valid captured data (login tokens, session cookies) is retransmitted. Defenses: timestamps/nonces, sequence numbers (IPSec), and short token expiry." },
  { id: "cn92", diff: "medium", topic: "Security", q: "What is port scanning and how do attackers use it?", opts: ["Measuring available bandwidth on specific network ports", "Probing TCP/UDP ports to discover running services and potential vulnerabilities for reconnaissance", "Encrypting data on specific protocol ports", "Assigning dynamic port numbers to running applications"], ans: 1, exp: "Port scanning (Nmap is the classic tool) probes ports to identify open services. Attackers use this to build a map of attack surface before exploitation." },
  { id: "cn93", diff: "medium", topic: "Security", q: "What is the difference between symmetric and asymmetric encryption?", opts: ["Symmetric is slower; asymmetric is always faster", "Symmetric uses one shared key (fast, e.g., AES); asymmetric uses a public/private key pair (slower, solves key distribution, e.g., RSA)", "Symmetric is used for authentication; asymmetric is for bulk data encryption", "Both are identical in performance and security properties"], ans: 1, exp: "Symmetric (AES, ChaCha20): fast, ideal for bulk data, but key must be securely shared. Asymmetric (RSA, ECDH): solves key distribution but is computationally expensive. TLS uses asymmetric for handshake, symmetric for data." },
  { id: "cn94", diff: "medium", topic: "Security", q: "What is the role of a Certificate Authority (CA) in TLS/PKI?", opts: ["Encrypts web traffic directly between client and server", "Issues and digitally signs certificates, binding a public key to an identity — browsers trust CAs to validate server authenticity", "Assigns IP addresses to web servers for certificate issuance", "Generates the symmetric session keys used to encrypt TLS traffic"], ans: 1, exp: "A CA vouches for identity. The server's certificate (signed by the CA) contains its public key. The client verifies the CA's signature using its root certificate (pre-installed in browsers/OS). This is the chain of trust." },
  { id: "cn95", diff: "medium", topic: "Security", q: "What is a VPN and how does it provide security?", opts: ["A virtual physical network built with dedicated leased lines", "An encrypted tunnel over the public internet — data is encrypted at source, tunneled, and decrypted at destination", "A protocol that makes network routing faster", "A special type of VLAN for remote users"], ans: 1, exp: "A VPN encapsulates and encrypts traffic between endpoints over the public internet. IPSec VPN encrypts at Layer 3. SSL/TLS VPN uses HTTPS. WireGuard is a modern, fast alternative." },
  { id: "cn96", diff: "medium", topic: "Security", q: "What is OAuth 2.0's role in API security?", opts: ["OAuth 2.0 is a network routing and authentication protocol", "OAuth 2.0 is an authorization framework — issues scoped access tokens to third-party apps without exposing user credentials", "OAuth 2.0 encrypts all API traffic between client and server", "OAuth 2.0 is a direct replacement for TLS in API communications"], ans: 1, exp: "OAuth 2.0 delegates access: instead of sharing passwords, users grant third-party apps access tokens with specific scopes. Not an authentication protocol — that's OpenID Connect." },
  { id: "cn97", diff: "medium", topic: "TCP/IP", q: "What is the purpose of the TCP sliding window?", opts: ["Encrypt data segments during transmission", "Allow multiple segments to be sent before waiting for ACK, based on receiver's advertised buffer size", "Fragment large segments into smaller IP packets", "Handle DNS resolution within the TCP stack"], ans: 1, exp: "Without sliding window, TCP would wait for an ACK per segment (stop-and-wait) — very slow over high-latency links. Sliding window allows 'window size' bytes to be in flight simultaneously." },
  { id: "cn98", diff: "medium", topic: "TCP/IP", q: "What is the purpose of TCP's TIME_WAIT state?", opts: ["Wait for the remote server to close the connection first", "Ensure any delayed duplicate segments from the old connection expire before a new connection with same IP/port reuses them", "Buffer additional incoming data after connection close", "Trigger retransmission of the final FIN packet"], ans: 1, exp: "TIME_WAIT lasts 2×MSL (Maximum Segment Lifetime, typically 60s). It ensures the final ACK is delivered, and delayed segments from the old connection expire before a new connection begins." },
  { id: "cn99", diff: "medium", topic: "TCP/IP", q: "What is the Nagle algorithm in TCP?", opts: ["A congestion control mechanism for high-bandwidth links", "Combines small outgoing TCP segments into larger ones to reduce packet overhead — can add latency in interactive applications", "A retransmission algorithm for recovering from burst packet loss", "A flow control mechanism that adjusts the receiver window size"], ans: 1, exp: "Nagle buffers small writes until a full MSS or an ACK arrives. Great for bulk transfers, but harmful for interactive protocols (SSH keystrokes, online gaming). Disabled with TCP_NODELAY." },
  { id: "cn100", diff: "medium", topic: "TCP/IP", q: "How does SACK (Selective Acknowledgment) improve TCP efficiency?", opts: ["TCP doesn't handle out-of-order packet delivery at all", "Without SACK, TCP retransmits from the first gap onward. SACK allows the receiver to report non-contiguous received ranges, so only truly missing segments are retransmitted", "SACK reduces the TCP window size to prevent congestion", "SACK is a mechanism used only in UDP-based reliable protocols"], ans: 1, exp: "Classic TCP (without SACK): if segment 5 of 10 is lost, retransmit from 5 even if 6-10 arrived. With SACK: receiver says 'I have 1-4 and 6-10, only missing 5.' Sender retransmits only segment 5." },
  { id: "cn101", diff: "medium", topic: "TCP/IP", q: "TCP zero window: the receiver sets window size to 0. What happens?", opts: ["The TCP connection is immediately terminated by both sides", "The sender stops transmitting and periodically sends TCP Zero Window Probe segments to check if the window has reopened", "The sender continues transmitting, buffering data at the router", "The router buffers all data until the receiver window reopens"], ans: 1, exp: "Zero window = receiver buffer is full (back-pressure). The sender pauses but sends Zero Window Probes to check for window updates. When the application drains the buffer, the receiver sends a Window Update." },
  { id: "cn102", diff: "medium", topic: "TCP/IP", q: "What is TCP head-of-line blocking and why did HTTP/2 not fully solve it?", opts: ["HOL blocking is a Layer 2 issue unrelated to TCP behavior", "A lost TCP segment blocks all subsequent data in the byte stream. HTTP/2 multiplexes streams over one TCP connection — all streams stall on any single TCP loss. HTTP/3/QUIC solves this", "HTTP/2 completely eliminated HOL blocking through stream multiplexing", "HOL blocking only affects UDP-based transport protocols"], ans: 1, exp: "TCP delivers a byte stream in order. One lost segment stalls everything behind it. HTTP/2's multiplexing over one TCP connection means all streams are blocked by a single TCP loss. HTTP/3 over QUIC runs each stream independently." },
  { id: "cn103", diff: "medium", topic: "TCP/IP", q: "IPv6 uses which mechanism instead of broadcast?", opts: ["Anycast — one-to-nearest delivery", "Multicast — one-to-many delivery to subscribed groups", "Regular unicast with a higher TTL", "Broadcast with TTL limited to 1 hop"], ans: 1, exp: "IPv6 eliminates broadcast. Neighbor Discovery (NDP, which replaces ARP) uses link-local multicast. All-routers multicast (FF02::2), Solicited-Node multicast addresses reduce unnecessary traffic." },
  { id: "cn104", diff: "medium", topic: "Data Link", q: "What is the purpose of the CRC field in an Ethernet frame?", opts: ["Identify the original sender's hardware address", "Encrypt the payload for transmission security", "Detect bit errors introduced during transmission", "Fragment frames that exceed the MTU"], ans: 2, exp: "CRC (Cyclic Redundancy Check) is a checksum appended to the frame. The receiver recalculates CRC; if it doesn't match, the frame is silently discarded." },
  { id: "cn105", diff: "medium", topic: "Data Link", q: "What is the purpose of the 802.1Q tag in Ethernet frames?", opts: ["Fragment Ethernet frames larger than the MTU", "Insert a 4-byte VLAN identifier tag to carry multiple VLANs across trunk links", "Encrypt the frame payload for inter-VLAN security", "Add precise timestamps for latency measurement"], ans: 1, exp: "802.1Q inserts a 4-byte tag between the source MAC and EtherType: 2-byte TPID (0x8100) + 2-byte TCI (3-bit priority + 1-bit DEI + 12-bit VLAN ID). This allows 4094 VLANs on a single trunk." },
  { id: "cn106", diff: "medium", topic: "Data Link", q: "What is CSMA/CA and where is it used?", opts: ["Used in Ethernet to detect collisions after they occur", "Used in 802.11 Wi-Fi to avoid collisions — wireless nodes can't detect collisions while transmitting, so they avoid them proactively", "Used exclusively in fiber optic networks", "Used only in legacy half-duplex Ethernet segments"], ans: 1, exp: "Wi-Fi can't detect collisions (half-duplex wireless). CSMA/CA uses: listen before transmit, RTS/CTS optional handshake, random backoff timers. ACKs confirm delivery." },
  { id: "cn107", diff: "medium", topic: "Data Link", q: "What is the maximum payload (MTU) of a standard Ethernet frame?", opts: ["512 bytes", "1024 bytes", "1500 bytes", "9000 bytes (Jumbo frames only)"], ans: 2, exp: "Standard Ethernet MTU = 1500 bytes. Jumbo frames (up to 9000 bytes) require explicit support on all devices and can improve throughput for storage traffic." },
  { id: "cn108", diff: "medium", topic: "Data Link", q: "What is the difference between half-duplex and full-duplex communication?", opts: ["Half-duplex is encrypted; full-duplex is unencrypted", "Half-duplex allows simultaneous bidirectional; full-duplex is one direction at a time", "Full-duplex allows simultaneous send and receive; half-duplex is one direction at a time (walkie-talkie model)", "Half-duplex uses fiber optic; full-duplex uses copper cables"], ans: 2, exp: "Full-duplex (modern switched Ethernet): send and receive simultaneously, no collisions, CSMA/CD disabled. Half-duplex (hubs, old coax Ethernet): only one at a time — CSMA/CD active." },
  { id: "cn109", diff: "medium", topic: "App Layer", q: "A user accesses www.example.com. What is the correct order of protocol involvement?", opts: ["HTTP → DNS → TCP → IP", "DNS resolution → TCP handshake → IP routing → HTTP request", "DNS → IP routing → TCP → HTTP", "TCP handshake → DNS → HTTP → IP"], ans: 1, exp: "Step-by-step: 1) DNS resolves domain → IP, 2) TCP three-way handshake, 3) IP routes each packet, 4) HTTP GET request is sent and response received." },
  { id: "cn110", diff: "medium", topic: "App Layer", q: "What is the key difference between HTTP/1.1 and HTTP/2?", opts: ["HTTP/2 uses UDP instead of TCP", "HTTP/2 supports multiplexing — multiple requests over a single connection simultaneously, with header compression and binary framing", "HTTP/1.1 supports compression; HTTP/2 dropped it", "HTTP/2 is unencrypted; HTTP/1.1 supports TLS"], ans: 1, exp: "HTTP/1.1 suffers from HOL blocking (one request at a time per connection). HTTP/2 introduces multiplexing (multiple streams), HPACK header compression, and binary framing." },
  { id: "cn111", diff: "medium", topic: "App Layer", q: "What is the function of a CDN (Content Delivery Network)?", opts: ["A protocol for encrypting content at the application layer", "Caches and serves content from edge servers geographically close to users — reducing latency and origin server load", "Acts as a web application firewall between clients and servers", "A DNS-based load balancer that only routes requests, not content"], ans: 1, exp: "CDNs (Cloudflare, Akamai, AWS CloudFront) cache static assets on PoPs worldwide. Users connect to the nearest PoP — reducing RTT, offloading origin, and improving availability." },
  { id: "cn112", diff: "medium", topic: "App Layer", q: "HTTP is stateless. How do web applications maintain state across requests?", opts: ["HTTP/2 added native stateful session support", "Cookies, session tokens, and JWT are application-layer mechanisms that simulate statefulness over stateless HTTP", "HTTP is not actually stateless — TCP connection persistence provides state", "Only TCP keep-alive makes HTTP stateful across requests"], ans: 1, exp: "HTTP has no built-in memory between requests. Cookies persist tokens on the client. Server-side sessions link session IDs to server-stored state. JWTs carry signed claims in the token itself." },
  { id: "cn113", diff: "medium", topic: "App Layer", q: "A company's email server uses port 587 instead of 25. What is the likely reason?", opts: ["Port 25 is reserved exclusively for POP3 email retrieval", "Port 587 (SMTP submission with STARTTLS) is for authenticated client submission; ISPs block port 25 to prevent spam", "Port 587 is inherently faster than port 25 for SMTP", "Port 587 uses UDP while port 25 uses TCP"], ans: 1, exp: "Port 25: server-to-server SMTP relay (often blocked by ISPs to prevent spam). Port 587: SMTP submission — clients authenticate before sending, with STARTTLS for encryption." },
  { id: "cn114", diff: "hard", topic: "Routing", q: "BGP best-path: Peer A has AS_PATH length 3; Peer B has longer AS_PATH but higher LOCAL_PREF. Which is preferred?", opts: ["Peer A — shorter AS_PATH always takes precedence", "Peer B — LOCAL_PREF is evaluated before AS_PATH length in BGP best-path selection", "Peer A — eBGP routes are always preferred over all other attributes", "Both routes are installed in the table with equal cost"], ans: 1, exp: "BGP best-path order: Weight → LOCAL_PREF → Locally originated → AS_PATH length → Origin → MED → eBGP > iBGP → IGP metric → Router ID. LOCAL_PREF (step 2) is evaluated before AS_PATH (step 4)." },
  { id: "cn115", diff: "hard", topic: "Routing", q: "What is the difference between iBGP and eBGP, and why does iBGP require a full mesh or route reflectors?", opts: ["iBGP is within an AS; eBGP is between ASes. iBGP requires full mesh because it does not re-advertise routes learned from one iBGP peer to another", "iBGP is faster than eBGP due to shorter paths within an AS", "eBGP requires a full mesh; iBGP does not have this requirement", "They are identical protocols except for their administrative distance values"], ans: 0, exp: "iBGP split horizon: routes learned from iBGP peers are NOT re-advertised to other iBGP peers (loop prevention). This creates an iBGP full-mesh requirement (n(n-1)/2 sessions). Route Reflectors or BGP Confederations scale iBGP without full mesh." },
  { id: "cn116", diff: "hard", topic: "Routing", q: "What is OSPF Area 0 and what happens if an area can't connect to it directly?", opts: ["Area 0 is for external routes; internal areas don't need to connect to it", "Area 0 is the backbone; all areas must connect to it. Discontiguous areas use OSPF virtual links through a transit area", "Area 0 is an optional performance optimization", "Each area in OSPF uses its own independent algorithm and doesn't need Area 0"], ans: 1, exp: "All OSPF areas must connect to Area 0 (backbone) to receive inter-area routes from ABRs. If a non-backbone area is disconnected, a virtual link is configured through a transit area." },
  { id: "cn117", diff: "hard", topic: "Routing", q: "In OSPF, what is the difference between E1 and E2 external LSAs (Type 5)?", opts: ["E1 is for inter-area routes; E2 is for intra-area routes", "E1 adds the internal OSPF path cost to the external cost (cumulative); E2 uses only the external cost (constant) — E1 gives more accurate end-to-end cost comparison", "E2 is always preferred over E1 by the OSPF algorithm", "E1 uses hop count; E2 uses bandwidth as the metric"], ans: 1, exp: "E2 (default): the metric never changes as the route is advertised inside OSPF — only the external cost matters. E1: internal OSPF cost is added to the external cost, reflecting true end-to-end cost." },
  { id: "cn118", diff: "hard", topic: "Routing", q: "What is ECMP (Equal-Cost Multi-Path routing) and what limitation affects stateful flows?", opts: ["ECMP is a routing protocol for multicast traffic distribution", "ECMP installs multiple equal-cost routes, distributing traffic across paths; limitation: asymmetric routing can break stateful firewalls that track sessions directionally", "ECMP is a load-balancing protocol that only works with BGP", "ECMP guarantees packet ordering across all distributed paths"], ans: 1, exp: "ECMP installs multiple next-hops for the same destination. Per-flow hashing keeps packets of the same flow on the same path. Asymmetric routing (different paths in/out) can break stateful firewalls/NAT." },
  { id: "cn119", diff: "hard", topic: "Routing", q: "What is MPLS and how does label switching differ from traditional IP routing?", opts: ["MPLS is a network security protocol for encrypting routing tables", "MPLS adds a label stack between L2 and L3; LSRs forward based on exact-match label lookups — faster than IP LPM, enabling VPNs, TE, and QoS at scale", "MPLS permanently replaces IP addresses with labels end-to-end", "MPLS requires physically separate hardware infrastructure from IP networks"], ans: 1, exp: "MPLS labels (20-bit) are pushed at the ingress LER and popped at the egress LER. Transit LSRs swap labels using a simple exact-match table — much faster than IP LPM. Enables L3VPNs, Traffic Engineering (RSVP-TE), and QoS." },
  { id: "cn120", diff: "hard", topic: "Routing", q: "What is Segment Routing (SR) and how does it simplify MPLS Traffic Engineering?", opts: ["Segment Routing is a replacement for BGP in large-scale networks", "SR encodes the explicit path as a stack of Segment IDs in the packet header — transit routers need no per-LSP state (unlike RSVP-TE), with only the ingress node knowing the path", "SR requires a full mesh of tunnels between all routers", "SR uses hop count for path selection and cannot support bandwidth constraints"], ans: 1, exp: "RSVP-TE requires per-LSP signaling state at every router. SR-MPLS or SRv6 embeds the entire path as an ordered list of SIDs in the packet. Transit nodes just follow instructions — no per-path state, simplifying TE." },
  { id: "cn121", diff: "hard", topic: "Routing", q: "What is BGP NEXT_HOP processing and why is 'next-hop-self' important in iBGP?", opts: ["NEXT_HOP is always set to the originating router's address in all BGP sessions", "iBGP preserves the eBGP peer's IP as NEXT_HOP — which internal routers may lack a route to. 'next-hop-self' replaces it with the iBGP router's own address, ensuring reachability", "NEXT_HOP is only relevant in IPv6 BGP sessions", "'next-hop-self' is only required when using BGP route reflectors"], ans: 1, exp: "When an eBGP-learned route is re-advertised via iBGP, the NEXT_HOP attribute retains the external eBGP peer's IP. Internal routers may not have a route to that external IP. Configuring 'next-hop-self' changes NEXT_HOP to the advertising router's interface address." },
  { id: "cn122", diff: "hard", topic: "Routing", q: "What is a BGP confederation and when is it preferred over route reflectors?", opts: ["A BGP confederation is merely a marketing term for iBGP optimization", "Confederations divide an AS into sub-ASes with eBGP-like sessions between them, preserving full BGP attributes (MED, LOCAL_PREF) across the AS — preferred when full attribute transparency and complex policy are needed", "Confederations are always simpler to implement than route reflectors", "Confederations entirely replace iBGP, eliminating the need for peer relationships"], ans: 1, exp: "Route reflectors may distort MED comparisons across clusters. BGP confederations create sub-ASes with genuine eBGP between them — attributes like MED are properly compared. Trade-off: more complex configuration but more precise policy control." },
  { id: "cn123", diff: "hard", topic: "Routing", q: "What is the count-to-infinity problem in RIP and what is its maximum impact?", opts: ["Routers loop packets indefinitely with unbounded metric growth", "After a link failure, routers iteratively increase metrics from stale information; in RIP the max is 15 update cycles (×30s each) before declaring the route unreachable", "Routes are immediately deleted from all routers when a failure is detected", "Count-to-infinity only affects OSPF networks, not distance-vector protocols"], ans: 1, exp: "Example: R1-R2-R3, R3's link fails. R2 thinks R1 can still reach R3 (old advertisement). They increment the metric back and forth: 2→3→4→...→16. At 16 (infinity in RIP), the route is finally removed. This can take 7.5+ minutes with 30s timers." },
  { id: "cn124", diff: "hard", topic: "Routing", q: "What is RTBH (Remotely Triggered Black Hole) routing and how does it mitigate DDoS?", opts: ["RTBH is a misconfigured static route that causes packet loss", "RTBH uses BGP to signal upstream ISPs to discard traffic destined to a victim /32 at the network edge, stopping DDoS traffic before it enters your network", "RTBH is a hidden BGP route never advertised to any peers", "RTBH is a routing technique that bypasses firewall inspection rules"], ans: 1, exp: "During a DDoS, announce victim_IP/32 with a BGP community that triggers upstream ISPs to route it to Null0. DDoS traffic is absorbed at the ISP edge. Trade-off: the attacked IP becomes unreachable." },
  { id: "cn125", diff: "hard", topic: "Congestion", q: "TCP CUBIC vs. TCP Reno: why does CUBIC outperform Reno on high-BDP networks?", opts: ["CUBIC uses faster packet retransmission than Reno", "CUBIC uses a cubic function for cwnd growth based on time since last loss — recovering faster and growing more aggressively; Reno's linear growth is too conservative for high-bandwidth, high-latency paths", "CUBIC completely disables the Slow Start phase", "CUBIC uses UDP internally to bypass TCP congestion signals"], ans: 1, exp: "Reno's Congestion Avoidance: +1 MSS per RTT — too slow to fill a 10Gbps × 100ms pipe. CUBIC: w(t) = C(t-K)³ + w_max — grows aggressively when far from the last loss point, converges smoothly near it." },
  { id: "cn126", diff: "hard", topic: "Congestion", q: "What is BBR (Bottleneck Bandwidth and RTT) and how does it fundamentally differ from loss-based algorithms?", opts: ["BBR is loss-based like Reno, just with a different backoff strategy", "BBR models the network path (bottleneck BW × min RTT) to set the send rate directly — it doesn't use packet loss as the primary signal, avoiding buffer inflation and achieving better throughput on high-latency or lossy paths", "BBR is designed exclusively for UDP-based protocols", "BBR is functionally equivalent to CUBIC with just different naming"], ans: 1, exp: "Loss-based algorithms fill buffers until packets drop — causing high queuing latency. BBR continuously measures bottleneck bandwidth (max delivery rate) and min RTT (min latency), sending at the optimal rate without filling buffers." },
  { id: "cn127", diff: "hard", topic: "Congestion", q: "What is Bufferbloat and how does it affect interactive applications?", opts: ["Bufferbloat refers to having too many network buffers configured in router hardware", "Excessively large router/modem buffers cause seconds of queuing latency during congestion — bulk transfers maintain throughput but interactive apps (VoIP, gaming) experience intolerable lag", "Bufferbloat is a type of buffer overflow security attack", "Bufferbloat is a memory leak that occurs in routing table management"], ans: 1, exp: "Large buffers are filled during bulk transfers, creating a queue. Packets spend 500ms+ in the queue, killing interactive latency. CoDel (Controlled Delay) and FQ-CoDel keep queues short while maintaining throughput." },
  { id: "cn128", diff: "hard", topic: "Congestion", q: "What is the difference between TCP Tahoe and TCP Reno after detecting packet loss?", opts: ["TCP Tahoe and Reno handle all types of loss identically", "Tahoe always resets cwnd to 1 MSS on any loss detection. Reno differentiates: triple duplicate ACKs trigger Fast Recovery (cwnd=ssthresh, not 1), avoiding expensive full Slow Start", "Reno is the older algorithm; Tahoe was developed as its replacement", "Tahoe supports ECN natively; Reno does not include ECN support"], ans: 1, exp: "TCP Tahoe: any loss (timeout OR triple dup ACK) → ssthresh=cwnd/2, cwnd=1, restart Slow Start. TCP Reno: timeout → same as Tahoe. Triple dup ACK → Fast Retransmit + Fast Recovery: ssthresh=cwnd/2, cwnd=ssthresh." },
  { id: "cn129", diff: "hard", topic: "Congestion", q: "What is the Bandwidth-Delay Product (BDP) and its implication for TCP buffer tuning?", opts: ["BDP measures the total router CPU capacity required for network traffic", "BDP = bandwidth × RTT = the amount of data that must be 'in flight' to fully utilize a link. Default OS TCP buffers are often too small for high-BDP paths, capping throughput", "BDP is relevant only for UDP-based applications and media streaming", "Larger BDP automatically improves TCP throughput without any configuration changes"], ans: 1, exp: "Example: 1Gbps × 100ms RTT = 12.5MB BDP. If TCP socket buffer is capped at 256KB, max throughput = 256KB / 0.1s = 20Mbps — only 2% of link capacity! Tune with tcp_rmem/tcp_wmem on Linux." },
  { id: "cn130", diff: "hard", topic: "Congestion", q: "QUIC runs over UDP but implements reliability. What specific advantage does this give HTTP/3?", opts: ["Lower encryption overhead compared to TLS 1.3 over TCP", "Eliminates transport-layer head-of-line blocking — a lost UDP datagram only blocks its own QUIC stream, not all other concurrent streams", "Skips the connection establishment phase entirely for all connections", "QUIC removes the need for any congestion control mechanism"], ans: 1, exp: "HTTP/2 over TCP: all multiplexed streams share one TCP byte stream. One lost TCP segment blocks ALL streams. HTTP/3 over QUIC: each stream is independently reliable. A lost packet only affects its own stream. Plus 0-RTT and built-in TLS 1.3." },
  { id: "cn131", diff: "hard", topic: "Security", q: "Why doesn't HTTPS prevent all Man-in-the-Middle attacks? What additional mechanisms are needed?", opts: ["HTTPS with a valid certificate prevents all possible MITM attacks completely", "HTTPS can be bypassed via SSL stripping (downgrade to HTTP) or rogue/compromised CAs. HSTS (preloading) and Certificate Transparency logs provide additional protection", "HTTPS is only vulnerable to MITM on HTTP/1.1 connections", "HTTPS only protects data at rest on the server, not data in transit"], ans: 1, exp: "SSL Stripping: attacker intercepts first HTTP request before HTTPS redirect. Fix: HSTS with preloading (browser always goes directly to HTTPS). Rogue CAs can issue fraudulent certs — CT logs make this detectable." },
  { id: "cn132", diff: "hard", topic: "Security", q: "What is BGP hijacking and how does RPKI mitigate it?", opts: ["BGP hijacking is a physical attack on internet cables; RPKI encrypts fiber connections", "A malicious AS advertises IP prefixes it doesn't own to attract traffic through it; RPKI cryptographically binds prefixes to authorized origin ASes using signed ROA objects", "BGP hijacking is a DNS-based attack; RPKI provides DNS-level protection", "BGP hijacking only affects local area networks; ISPs are automatically protected"], ans: 1, exp: "Examples: Pakistan Telecom hijacking YouTube (2008), Rostelecom hijacking financial routes (2020). RPKI: prefix owners create Route Origin Authorizations (ROAs) signed with their IANA-allocated key. Routers validate: if no ROA or wrong ASN → Invalid → drop." },
  { id: "cn133", diff: "hard", topic: "Security", q: "What is a timing side-channel attack? Provide a concrete network security example.", opts: ["A DoS attack that exploits precise timestamps in network packet headers", "An attack that exploits measurable differences in execution time to infer secret information — e.g., TLS CBC-mode padding oracle attacks measuring server response time differences", "A replay attack that uses expired authentication timestamps", "A Man-in-the-Middle attack that exploits NTP time synchronization"], ans: 1, exp: "Lucky 13: TLS CBC-mode HMAC verification took slightly different time based on padding length. An active attacker could send crafted ciphertexts and measure response times (nanosecond differences) to statistically determine plaintext content." },
  { id: "cn134", diff: "hard", topic: "Security", q: "What is HSTS (HTTP Strict Transport Security) and what specific attack does it prevent?", opts: ["HSTS is a response header that speeds up HTTPS connections through caching", "HSTS instructs browsers to always connect via HTTPS for a domain (with max-age), preventing SSL stripping attacks that downgrade the initial connection to HTTP", "HSTS is a certificate validation mechanism that pins specific CA certificates", "HSTS is a rate-limiting header that prevents DDoS attacks against HTTPS servers"], ans: 1, exp: "Without HSTS: attacker intercepts first HTTP request (before redirect to HTTPS) and maintains HTTP with victim. With HSTS: browser remembers it must use HTTPS directly — even the first request is HTTPS, eliminating the downgrade window." },
  { id: "cn135", diff: "hard", topic: "Security", q: "What is a VLAN hopping attack and how is it prevented?", opts: ["Accessing other VLANs by sending traffic through a NAT device", "Double-tagging attack: crafting frames with two 802.1Q tags where the outer tag matches the native VLAN; or Switch Spoofing: exploiting DTP to form an unauthorized trunk — both allow access to other VLANs", "VLAN hopping is a physical cable reconnection attack", "VLAN hopping is an ARP-based attack that works only on IPv6 networks"], ans: 1, exp: "Double-tag: send frame with outer VLAN=native (stripped by first switch) and inner VLAN=target. Switch spoofing: force DTP negotiation. Prevention: disable DTP ('switchport nonegotiate'), set native VLAN to an unused ID, enable BPDU Guard." },
  { id: "cn136", diff: "hard", topic: "Security", q: "What is a supply chain attack and how did SolarWinds demonstrate this vector?", opts: ["An attack targeting physical network supply warehouses and shipping infrastructure", "Attackers compromise a trusted software vendor's build pipeline to distribute trojaned updates — SolarWinds: SUNBURST backdoor was inserted into digitally-signed Orion updates, silently infecting 18,000+ organizations", "An attack conducted exclusively through ISP infrastructure and upstream providers", "A hardware trojan physically inserted into network cables during manufacturing"], ans: 1, exp: "SolarWinds 2020: attackers (APT29/Cozy Bear) compromised SolarWinds' build server, injecting SUNBURST backdoor into Orion software updates. The updates were digitally signed — customers trusted them. Defense: SBOM, reproducible builds, code signing with hardware keys." },
  { id: "cn137", diff: "hard", topic: "Security", q: "What is AES-ECB mode vulnerable to in a chosen-plaintext attack (CPA)?", opts: ["ECB is vulnerable to brute-force attacks on the AES key length", "ECB encrypts each block independently — identical plaintext blocks produce identical ciphertext blocks, leaking data patterns. Secure modes (CBC, CTR, GCM) use IVs/nonces to prevent this", "ECB mode is only vulnerable to attacks with physical access to hardware", "CPA only affects asymmetric encryption algorithms, not symmetric block ciphers"], ans: 1, exp: "AES-ECB: each 16-byte block is encrypted identically. The classic example: encrypting a bitmap image with ECB mode — the image structure remains clearly visible in the ciphertext. Modes with IVs/nonces ensure identical plaintexts produce different ciphertexts." },
  { id: "cn138", diff: "hard", topic: "Security", q: "What is Perfect Forward Secrecy (PFS) and why is it critical in TLS?", opts: ["PFS is encryption that continues to protect data even after a session has ended (at-rest encryption)", "PFS uses ephemeral key exchange (ECDHE/DHE) so that compromise of the server's long-term private key cannot decrypt previously recorded sessions — each session generates unique throwaway keys", "PFS is a mechanism specifically designed to prevent replay attacks in TLS sessions", "PFS is a certificate pinning technique to prevent rogue Certificate Authority attacks"], ans: 1, exp: "Without PFS: attacker records encrypted TLS sessions, later obtains server private key → decrypts all historical sessions. With PFS (ECDHE): session key = ephemeral keypair × ephemeral keypair — discarded after use. Required for compliance (PCI-DSS, HIPAA)." },
  { id: "cn139", diff: "hard", topic: "Security", q: "What is the difference between an IDS and an IPS in terms of deployment and capability?", opts: ["IDS blocks malicious traffic in real time; IPS only monitors and sends alerts", "IDS passively monitors a copy of traffic (out-of-band) and alerts; IPS is deployed inline and actively blocks malicious traffic in real time — but adds latency and false positives can block legitimate traffic", "They are functionally identical products with different branding", "IDS is designed for wired networks; IPS is designed specifically for wireless environments"], ans: 1, exp: "IDS (out-of-band/span port): sees a copy of traffic, generates alerts, zero performance impact, cannot block. IPS (inline): can drop/reset malicious flows in real time but adds latency; false positives can cause legitimate traffic outages. NGFW often integrates IPS functionality." },
  { id: "cn140", diff: "hard", topic: "Security", q: "What is a zero-day vulnerability and why is it uniquely dangerous?", opts: ["A software vulnerability that was discovered within 24 hours of the software being released", "A publicly undisclosed vulnerability with no available vendor patch — attackers can exploit it freely while defenders have zero protection until a patch or mitigation is available", "A software bug that only affects brand-new versions of software releases", "A denial-of-service attack that targets application startup and zero-state initialization"], ans: 1, exp: "Zero-days are valuable on the black market (millions for iOS/browser zero-days). Stuxnet used 4 zero-days simultaneously. Defenders rely on behavioral detection, network segmentation, and least-privilege to limit zero-day blast radius." },
  { id: "cn141", diff: "hard", topic: "Security", q: "What is micro-segmentation in Zero Trust network architecture?", opts: ["Dividing an IP block into many small /30 subnets for address efficiency", "Applying fine-grained, identity-aware security policies at the individual workload/VM level for east-west (lateral) traffic — not just at the perimeter", "A VLAN-based traffic segmentation technique used for broadcast domain reduction", "Physically separating servers onto different network cards in a data center"], ans: 1, exp: "Traditional firewalls protect north-south (in/out) traffic but allow lateral movement once inside. Micro-segmentation (VMware NSX, Cisco ACI, Illumio) enforces policies between individual workloads." },
  { id: "cn142", diff: "hard", topic: "Security", q: "What is DNS cache poisoning (Kaminsky attack) and how does DNSSEC prevent it?", opts: ["Overloading a DNS server with queries to exhaust its cache capacity", "Injecting forged DNS responses into a resolver's cache by winning a race condition — pointing domains to attacker IPs. DNSSEC prevents this with cryptographic signatures on every DNS record", "A brute-force attack that guesses DNS resolver administrator passwords", "DNS cache poisoning only affects authoritative DNS servers, not recursive resolvers"], ans: 1, exp: "Kaminsky (2008): attacker floods resolver with forged UDP responses for a subdomain, racing to poison the cache. DNSSEC: every record is signed (RRSIG), resolver verifies the signature chain up to the root. Forged responses lack valid signatures → rejected." },
  { id: "cn143", diff: "hard", topic: "Security", q: "What is certificate transparency (CT) and what attack does it specifically mitigate?", opts: ["CT is a method to speed up certificate chain validation in browsers", "CT is a public, append-only, auditable log of all issued TLS certificates — it allows domain owners and researchers to detect unauthorized or misissued certificates from rogue CAs", "CT is a certificate compression algorithm that reduces TLS handshake size", "CT is a certificate revocation mechanism that replaces OCSP and CRL"], ans: 1, exp: "Without CT, a compromised CA could issue a certificate for google.com and use it for MITM — undetectable. CT logs record every issued certificate. Browsers require SCTs. Domain owners monitor logs and can quickly detect and revoke fraudulent certificates." },
  { id: "cn144", diff: "hard", topic: "Security", q: "What is OAuth 2.0 Authorization Code Flow and why is it more secure than the deprecated Implicit Flow?", opts: ["They are identical in security properties with different implementation names", "Authorization Code: the auth code is exchanged server-to-server for a token — access token never exposed in the browser. Implicit Flow: access token delivered in the URL fragment, visible to browser history, JS, and referrer headers — easily stolen", "Implicit Flow is actually more secure because it uses fewer network round trips", "Authorization Code Flow is only designed for mobile and native application clients"], ans: 1, exp: "Implicit Flow was designed for single-page apps before CORS. The access token appears in the URL fragment — exposed to browser history, JS, and referrer headers. Authorization Code + PKCE: only a short-lived code in the URL; token exchange happens server-side." },
  { id: "cn145", diff: "hard", topic: "Security", q: "What is an SSRF (Server-Side Request Forgery) attack and why is it critical in cloud environments?", opts: ["SSRF is a client-side injection attack targeting web browsers", "SSRF tricks a server into making HTTP requests to internal resources — in AWS, this can access the EC2 metadata service at 169.254.169.254, stealing IAM credentials with full cloud access", "SSRF is a DDoS attack that exhausts server connection pools", "SSRF is an SSL certificate forgery attack specific to cloud load balancers"], ans: 1, exp: "AWS IMDSv1 had no authentication — any SSRF could hit 169.254.169.254/latest/meta-data/iam/security-credentials/ and steal IAM role credentials. Capital One breach (2019) was a SSRF → credential theft → S3 data exfiltration. IMDSv2 requires session-oriented requests." },
  { id: "cn146", diff: "hard", topic: "Protocols", q: "What is QUIC 0-RTT connection establishment and what is the security trade-off?", opts: ["QUIC 0-RTT requires no encryption and bypasses TLS for connection setup speed", "QUIC uses cached TLS session parameters (PSK) from prior connections to send application data in the very first packet — 0-RTT data is vulnerable to replay attacks if the server accepts it non-idempotently", "QUIC 0-RTT is identical to TCP Fast Open in all security properties", "QUIC 0-RTT eliminates all need for congestion control during session resumption"], ans: 1, exp: "0-RTT: client caches session ticket from previous connection; in the next connection, sends app data immediately without waiting for a handshake. Replay risk: an attacker could resend the 0-RTT data. Mitigation: 0-RTT data should only be used for idempotent requests." },
  { id: "cn147", diff: "hard", topic: "Protocols", q: "What is TLS 1.3 and how does its handshake differ from TLS 1.2 in terms of latency?", opts: ["TLS 1.3 requires more round trips than TLS 1.2 due to stronger cipher requirements", "TLS 1.3 achieves 1-RTT handshake (vs TLS 1.2's 2-RTT) by combining key exchange with ClientHello, and supports 0-RTT session resumption. It also removed all weak ciphers", "TLS 1.3 removed cipher suite negotiation, breaking all legacy TLS 1.2 deployments", "TLS 1.3 is significantly slower than TLS 1.2 due to its stronger mandatory encryption requirements"], ans: 1, exp: "TLS 1.2: ClientHello → ServerHello (1 RTT) → Certificate+Finished (2nd RTT) → data. TLS 1.3: ClientHello includes key_share (ECDHE public key) → server can immediately compute session keys → data after 1 RTT. Also removed RSA key exchange, MD5/SHA-1, CBC cipher suites." },
  { id: "cn148", diff: "hard", topic: "Protocols", q: "What is SCTP (Stream Control Transmission Protocol) and what advantages does it offer over TCP?", opts: ["SCTP is identical to TCP but with UDP as its underlying transport", "SCTP supports multi-streaming (independent streams within one association, avoiding HOL blocking) and multi-homing (multiple IP endpoints per association for path failover)", "TCP is strictly more secure and reliable than SCTP in all network conditions", "SCTP is a faster but completely unreliable datagram protocol"], ans: 1, exp: "SCTP (RFC 4960): used in telecoms (SS7 over IP, Diameter). Multi-streaming: 16 independent streams per association — a stalled stream doesn't block others. Multi-homing: if one path fails, the association continues on another." },
  { id: "cn149", diff: "hard", topic: "Protocols", q: "How does OSPF prevent network instability from excessive LSA flooding?", opts: ["OSPF strictly limits LSAs to 10 per router per update cycle", "OSPF uses sequence numbers (duplicate detection), MaxAge (3600s to expire stale LSAs), MinLSInterval (5s minimum between refreshes), and area design to limit flooding scope", "OSPF drops all LSAs during congestion events to protect routing stability", "LSA flooding is handled by BGP, not by OSPF internally"], ans: 1, exp: "OSPF flooding controls: sequence numbers (ignore duplicates), 3600s MaxAge (stale LSA auto-expiry), MinLSInterval (5s between origin refreshes). Area design: Type 1/2 LSAs are area-scoped; ABRs/ASBRs summarize inter-area/external routes." },
  { id: "cn150", diff: "hard", topic: "Protocols", q: "What is the difference between distance-vector, link-state, and path-vector routing protocol classes?", opts: ["They are simply different names for the same underlying algorithm", "Distance-vector (RIP, EIGRP): share routing table with neighbors, prone to count-to-infinity. Link-state (OSPF, IS-IS): flood topology, build full map, run Dijkstra. Path-vector (BGP): share complete AS-path list, loop prevention via AS_PATH", "Link-state protocols use hop count; distance-vector protocols use Dijkstra's algorithm", "Path-vector routing is only used within local area networks and campus environments"], ans: 1, exp: "Distance-vector: 'routing by rumor' — only know what neighbors tell you. Converges slowly, loop-prone. Link-state: every router knows the full topology and independently computes optimal paths. Path-vector (BGP): exchanges the full list of ASes a route traverses — loop detection via AS_PATH, policy-rich routing." },
];

/* ═══════════════════════════════════════════════════════════════
   JAVA OOP — 260 Questions
═══════════════════════════════════════════════════════════════ */
const OOP_Q = [
  { id: "oop1", diff: "easy", topic: "Basics", q: "What does OOP stand for?", opts: ["Object Oriented Programming", "Object Oriented Protocol", "Ordered Object Programming", "Open Object Programming"], ans: 0, exp: "OOP stands for Object-Oriented Programming — a paradigm that organises software around objects (data + behaviour) rather than functions and logic." },
  { id: "oop2", diff: "easy", topic: "Basics", q: "Which of the following is NOT a pillar of OOP?", opts: ["Encapsulation", "Inheritance", "Compilation", "Polymorphism"], ans: 2, exp: "The four pillars of OOP are Encapsulation, Inheritance, Polymorphism, and Abstraction. Compilation is a build-process concept, not an OOP pillar." },
  { id: "oop3", diff: "easy", topic: "Class & Object", q: "What is a class in Java?", opts: ["A runtime instance", "A blueprint for creating objects", "A built-in data type", "A reserved keyword only"], ans: 1, exp: "A class is a template/blueprint that defines the properties (fields) and behaviours (methods) that its objects will have." },
  { id: "oop4", diff: "easy", topic: "Class & Object", q: "What is an object in Java?", opts: ["A keyword", "A primitive data type", "An instance of a class", "A method definition"], ans: 2, exp: "An object is a concrete instance of a class, created with the 'new' keyword. It occupies memory and has its own state." },
  { id: "oop5", diff: "easy", topic: "Class & Object", q: "Which keyword is used to create an object in Java?", opts: ["create", "object", "new", "make"], ans: 2, exp: "The 'new' keyword allocates memory on the heap for a new object and calls the constructor: MyClass obj = new MyClass();" },
  { id: "oop6", diff: "easy", topic: "Constructor", q: "What is a constructor in Java?", opts: ["A method that returns an object", "A special method called automatically when an object is created", "A static block", "A destructor method"], ans: 1, exp: "A constructor is a special method with the same name as the class, no return type, called automatically when 'new' is used to initialise the object." },
  { id: "oop7", diff: "easy", topic: "Constructor", q: "What is a default constructor?", opts: ["A constructor with parameters", "A constructor the compiler provides if none is defined", "A private constructor", "A static constructor"], ans: 1, exp: "If you write no constructor, Java provides a default no-arg constructor that initialises fields to default values (0, null, false)." },
  { id: "oop8", diff: "easy", topic: "Encapsulation", q: "Which access modifier makes a member accessible only within its own class?", opts: ["public", "protected", "default", "private"], ans: 3, exp: "'private' restricts access to the declaring class only. This is the core of encapsulation — hiding internal state." },
  { id: "oop9", diff: "easy", topic: "Encapsulation", q: "What are getter and setter methods used for?", opts: ["To delete objects", "To provide controlled access to private fields", "To override methods", "To define constructors"], ans: 1, exp: "Getters/setters allow read/write access to private fields while enabling validation, logging, or other logic — a key encapsulation technique." },
  { id: "oop10", diff: "easy", topic: "Inheritance", q: "Which keyword is used to inherit a class in Java?", opts: ["implements", "inherits", "extends", "super"], ans: 2, exp: "The 'extends' keyword establishes an IS-A relationship: class Dog extends Animal means Dog inherits all non-private members of Animal." },
  { id: "oop11", diff: "easy", topic: "Inheritance", q: "What is the parent class also called?", opts: ["Child class", "Derived class", "Super class", "Sub class"], ans: 2, exp: "The parent/base class is called the superclass. The child/derived class is called the subclass. 'super' keyword refers to the superclass." },
  { id: "oop12", diff: "easy", topic: "Inheritance", q: "Does Java support multiple inheritance through classes?", opts: ["Yes, always", "No, not through classes", "Yes, with 'extends' multiple", "Only in abstract classes"], ans: 1, exp: "Java does NOT support multiple class inheritance to avoid the 'diamond problem'. However, a class can implement multiple interfaces." },
  { id: "oop13", diff: "easy", topic: "Polymorphism", q: "What does polymorphism mean?", opts: ["Single form", "Many forms", "No form", "Static form"], ans: 1, exp: "Polymorphism (Greek: 'many forms') allows the same method name to behave differently based on context — at compile time (overloading) or runtime (overriding)." },
  { id: "oop14", diff: "easy", topic: "Polymorphism", q: "Which type of polymorphism is method overloading?", opts: ["Runtime polymorphism", "Dynamic polymorphism", "Compile-time polymorphism", "Interface polymorphism"], ans: 2, exp: "Method overloading is resolved at compile time (static binding) based on method signature — number, type, or order of parameters." },
  { id: "oop15", diff: "easy", topic: "Polymorphism", q: "Which type of polymorphism is method overriding?", opts: ["Compile-time polymorphism", "Static polymorphism", "Runtime polymorphism", "Early binding"], ans: 2, exp: "Method overriding is resolved at runtime (dynamic dispatch / late binding) based on the actual object type, not the reference type." },
  { id: "oop16", diff: "easy", topic: "Abstraction", q: "Which keyword is used to define an abstract class?", opts: ["interface", "virtual", "abstract", "static"], ans: 2, exp: "The 'abstract' keyword declares a class that cannot be instantiated and may contain abstract methods (declared without body)." },
  { id: "oop17", diff: "easy", topic: "Abstraction", q: "Can you instantiate an abstract class?", opts: ["Yes", "No", "Only with new keyword", "Only inside the same package"], ans: 1, exp: "Abstract classes cannot be instantiated directly. They must be subclassed, and the subclass must implement all abstract methods (or also be abstract)." },
  { id: "oop18", diff: "easy", topic: "Interface", q: "Which keyword is used to define an interface?", opts: ["abstract", "class", "interface", "implements"], ans: 2, exp: "The 'interface' keyword defines a contract — a set of method signatures that implementing classes must provide." },
  { id: "oop19", diff: "easy", topic: "Interface", q: "Which keyword does a class use to implement an interface?", opts: ["extends", "implements", "uses", "interface"], ans: 1, exp: "A class uses 'implements' to adopt an interface contract. It can implement multiple interfaces: class MyClass implements A, B, C {}" },
  { id: "oop20", diff: "easy", topic: "Interface", q: "Before Java 8, could interfaces have method bodies?", opts: ["Yes, always", "No, only abstract methods", "Yes, for static methods", "Yes, for private methods"], ans: 1, exp: "Before Java 8, interfaces could only have public abstract methods and public static final constants. Java 8 added default and static methods with bodies." },
  { id: "oop21", diff: "easy", topic: "Basics", q: "What is the 'this' keyword in Java?", opts: ["Refers to the superclass", "Refers to the current object instance", "Refers to the static context", "Refers to the interface"], ans: 1, exp: "'this' is a reference to the current object — used to distinguish instance variables from parameters with the same name, or to chain constructors." },
  { id: "oop22", diff: "easy", topic: "Basics", q: "What is the 'super' keyword used for?", opts: ["Reference current object", "Call child class method", "Reference the immediate superclass or its constructor/method", "Create static context"], ans: 2, exp: "'super' references the immediate parent class. Used as super() to call parent constructor, or super.method() to call an overridden parent method." },
  { id: "oop23", diff: "easy", topic: "Inheritance", q: "What is method overriding?", opts: ["Defining multiple methods with the same name", "Providing a new implementation in a subclass for a method defined in the superclass", "Creating abstract methods", "Hiding a method with static"], ans: 1, exp: "Method overriding re-implements a superclass method in a subclass with the same signature. The @Override annotation is recommended to catch errors at compile time." },
  { id: "oop24", diff: "easy", topic: "Polymorphism", q: "What is method overloading?", opts: ["Defining the same method in a subclass", "Defining multiple methods with the same name but different parameter lists in the same class", "Overriding a superclass method", "Hiding a static method"], ans: 1, exp: "Overloading: same method name, different parameter lists (number, type, or order). Return type alone does NOT differentiate overloaded methods." },
  { id: "oop25", diff: "easy", topic: "Basics", q: "What is a package in Java?", opts: ["A class", "A namespace that organises related classes and interfaces", "A method group", "A reserved keyword"], ans: 1, exp: "A package is a namespace mechanism that groups related classes/interfaces, avoids naming conflicts, and controls access with package-private visibility." },
  { id: "oop26", diff: "easy", topic: "Basics", q: "Which access modifier allows access from any class?", opts: ["private", "protected", "default", "public"], ans: 3, exp: "'public' allows access from any class in any package. Order from most restrictive: private < default < protected < public." },
  { id: "oop27", diff: "easy", topic: "Inheritance", q: "What does the 'final' keyword do when applied to a class?", opts: ["Makes it abstract", "Prevents it from being subclassed", "Makes all methods static", "Allows multiple inheritance"], ans: 1, exp: "A 'final' class cannot be extended/inherited (e.g., String, Integer). This is used for security and immutability." },
  { id: "oop28", diff: "easy", topic: "Inheritance", q: "What does 'final' do when applied to a method?", opts: ["Makes it abstract", "Prevents it from being overridden", "Makes it static", "Makes it private"], ans: 1, exp: "A 'final' method cannot be overridden in any subclass, ensuring its implementation remains unchanged throughout the hierarchy." },
  { id: "oop29", diff: "easy", topic: "Basics", q: "What is the root class of all Java classes?", opts: ["Class", "Object", "Base", "Root"], ans: 1, exp: "java.lang.Object is the root of the Java class hierarchy. Every class implicitly extends Object and inherits methods like equals(), hashCode(), toString()." },
  { id: "oop30", diff: "easy", topic: "Basics", q: "What is the purpose of the 'static' keyword on a field?", opts: ["Creates a new object for each field access", "Makes the field belong to the class rather than any instance", "Makes the field private", "Makes the field final"], ans: 1, exp: "Static fields (class variables) are shared across all instances. Only one copy exists regardless of how many objects are created." },
  { id: "oop31", diff: "easy", topic: "Basics", q: "Can a static method access instance variables directly?", opts: ["Yes", "No", "Only if they are final", "Only in the same package"], ans: 1, exp: "Static methods belong to the class, not an instance. They cannot directly access instance variables or call instance methods (no 'this' available)." },
  { id: "oop32", diff: "easy", topic: "Constructor", q: "Can a constructor be private?", opts: ["No", "Yes", "Only in abstract classes", "Only in interfaces"], ans: 1, exp: "Yes — private constructors are used in Singleton pattern, utility classes, and factory methods to control object creation." },
  { id: "oop33", diff: "easy", topic: "Constructor", q: "What is constructor chaining?", opts: ["Calling constructors of multiple classes", "Calling one constructor from another constructor in the same or parent class", "Overriding constructors", "Defining multiple constructors"], ans: 1, exp: "Constructor chaining: using this() to call another constructor in the same class, or super() to call a parent constructor. Must be the first statement." },
  { id: "oop34", diff: "easy", topic: "Interface", q: "What access modifier are interface methods by default (before Java 8)?", opts: ["private", "protected", "public abstract", "static"], ans: 2, exp: "Interface methods are implicitly 'public abstract' before Java 8. You don't need to write these modifiers — the compiler adds them automatically." },
  { id: "oop35", diff: "easy", topic: "Interface", q: "What type are interface variables/fields by default?", opts: ["private static", "public static final", "protected abstract", "default transient"], ans: 1, exp: "Interface fields are implicitly 'public static final' — they are constants. You must initialise them when declared." },
  { id: "oop36", diff: "easy", topic: "Abstraction", q: "What is the difference between abstract class and interface (pre-Java 8)?", opts: ["No difference", "Abstract class can have concrete methods and state; interface can only have abstract methods and constants", "Interface can extend classes", "Abstract class cannot have constructors"], ans: 1, exp: "Abstract class: can have constructors, instance fields, concrete methods, and abstract methods. Interface: only public abstract methods and public static final constants (pre-Java 8)." },
  { id: "oop37", diff: "easy", topic: "Encapsulation", q: "Which OOP principle does data hiding implement?", opts: ["Polymorphism", "Inheritance", "Encapsulation", "Abstraction"], ans: 2, exp: "Data hiding — making fields private and accessing via methods — is the core mechanism of encapsulation, protecting object state from external corruption." },
  { id: "oop38", diff: "easy", topic: "Basics", q: "What is a local variable?", opts: ["A variable declared inside a method or block", "A variable shared across all instances", "A variable declared with static", "A variable in an interface"], ans: 0, exp: "Local variables are declared inside methods, constructors, or blocks. They exist only during that scope's execution and must be explicitly initialised before use." },
  { id: "oop39", diff: "easy", topic: "Basics", q: "What is an instance variable?", opts: ["A variable declared inside a method", "A variable declared in a class but outside any method", "A static variable", "A variable in an interface"], ans: 1, exp: "Instance variables are declared in a class but outside methods. Each object gets its own copy, initialised to default values if not set explicitly." },
  { id: "oop40", diff: "easy", topic: "Polymorphism", q: "What is upcasting in Java?", opts: ["Converting subclass reference to superclass type", "Converting superclass to subclass", "Casting between unrelated classes", "Casting primitives to objects"], ans: 0, exp: "Upcasting: assigning a subclass object to a superclass reference — implicit and safe. e.g., Animal a = new Dog(); The Dog IS-AN Animal." },
  { id: "oop41", diff: "easy", topic: "Polymorphism", q: "What is downcasting?", opts: ["Converting superclass reference to subclass type", "Converting subclass to superclass", "Automatic casting", "Casting to interface"], ans: 0, exp: "Downcasting: explicitly casting a superclass reference back to the subclass type. Can throw ClassCastException if the actual object is not of that subclass." },
  { id: "oop42", diff: "easy", topic: "Basics", q: "What does 'instanceof' operator do?", opts: ["Creates an object", "Tests if an object is an instance of a class or interface", "Compares two objects", "Checks if a class is abstract"], ans: 1, exp: "'instanceof' returns true if the object is an instance of the specified class, subclass, or interface. Useful before downcasting to prevent ClassCastException." },
  { id: "oop43", diff: "easy", topic: "Inheritance", q: "How many classes can a Java class directly extend?", opts: ["Unlimited", "Two", "One", "Three"], ans: 2, exp: "Java supports single inheritance for classes — a class can extend only ONE other class. This avoids the diamond problem. Multiple inheritance is achieved via interfaces." },
  { id: "oop44", diff: "easy", topic: "Interface", q: "How many interfaces can a Java class implement?", opts: ["Only one", "Only two", "Any number", "Only three"], ans: 2, exp: "A class can implement any number of interfaces, providing Java's way to achieve multiple inheritance of type: class C implements A, B, D {}" },
  { id: "oop45", diff: "easy", topic: "Basics", q: "What is a wrapper class?", opts: ["A class that wraps a method", "A class that provides object representation of primitive types", "A class that extends Object", "A utility class"], ans: 1, exp: "Wrapper classes (Integer, Double, Boolean, etc.) wrap primitives into objects, enabling them to be used in collections, generics, and APIs that require objects." },
  { id: "oop46", diff: "easy", topic: "Basics", q: "What is autoboxing?", opts: ["Manual conversion of primitive to wrapper", "Automatic conversion of primitive to wrapper class object", "Converting a wrapper to String", "Creating an array of wrappers"], ans: 1, exp: "Autoboxing automatically converts a primitive (int) to its wrapper (Integer) when needed. Unboxing is the reverse. Introduced in Java 5." },
  { id: "oop47", diff: "easy", topic: "Basics", q: "What is the purpose of the 'toString()' method?", opts: ["Compares two objects", "Returns a string representation of the object", "Converts a class to interface", "Creates a copy of the object"], ans: 1, exp: "toString() is defined in Object and returns a string representation. Override it to provide meaningful output instead of the default hashCode-based string." },
  { id: "oop48", diff: "easy", topic: "Basics", q: "What does the 'equals()' method do by default (from Object)?", opts: ["Compares field values", "Compares object references (memory addresses)", "Compares hash codes", "Compares class names"], ans: 1, exp: "Object.equals() checks reference equality (==). Override it to compare field values for logical equality (e.g., String overrides it to compare character sequences)." },
  { id: "oop49", diff: "easy", topic: "Basics", q: "What is 'null' in Java?", opts: ["An empty string", "A zero integer", "A special literal meaning 'no object reference'", "A boolean false"], ans: 2, exp: "null is a special literal that can be assigned to any reference type, indicating the variable points to no object. Calling a method on null throws NullPointerException." },
  { id: "oop50", diff: "easy", topic: "Interface", q: "Can an interface extend another interface?", opts: ["No", "Yes, using implements", "Yes, using extends", "Only abstract interfaces"], ans: 2, exp: "Interfaces extend other interfaces using 'extends' (not implements). An interface can extend multiple interfaces: interface C extends A, B {}" },
  { id: "oop51", diff: "easy", topic: "Basics", q: "What is a static initializer block?", opts: ["A block that runs each time an object is created", "A block that runs once when the class is loaded", "A block inside a constructor", "A method with no return type"], ans: 1, exp: "A static { } block runs once when the class is first loaded by the JVM, before any objects are created. Used to initialise static variables with complex logic." },
  { id: "oop52", diff: "easy", topic: "Basics", q: "What is an instance initializer block?", opts: ["A block that runs once per class load", "A block that runs before every constructor call", "A block that replaces constructors", "A static block"], ans: 1, exp: "An instance initializer block { } (without static) runs before the constructor body every time an object is created. Useful for code shared across multiple constructors." },
  { id: "oop53", diff: "easy", topic: "Inheritance", q: "What is multilevel inheritance?", opts: ["A class extending multiple classes", "A chain where A extends B and B extends C", "Interfaces extending interfaces", "A class implementing multiple interfaces"], ans: 1, exp: "Multilevel inheritance: a chain A → B → C where C extends B which extends A. Java fully supports this via the single-inheritance chain." },
  { id: "oop54", diff: "easy", topic: "Inheritance", q: "What is hierarchical inheritance?", opts: ["Multiple classes extending the same parent", "One class extending multiple parents", "A chain of single extension", "Interfaces only"], ans: 0, exp: "Hierarchical inheritance: multiple classes (Dog, Cat, Bird) all extending the same base class (Animal). One parent, many children." },
  { id: "oop55", diff: "easy", topic: "Abstraction", q: "What is the purpose of abstraction in OOP?", opts: ["Hiding implementation details and exposing only essential features", "Making all methods static", "Preventing class creation", "Allowing multiple inheritance"], ans: 0, exp: "Abstraction hides complexity — users interact with a simple interface without knowing the internal implementation. Like driving a car without knowing the engine internals." },
  { id: "oop56", diff: "easy", topic: "Basics", q: "What is the difference between '==' and '.equals()' for String comparison?", opts: ["No difference", "== compares values, equals() compares references", "== compares references, equals() compares content", "Both compare references"], ans: 2, exp: "== for Strings checks reference equality (same object in memory). .equals() checks content equality (same characters). Always use .equals() for String value comparison." },
  { id: "oop57", diff: "easy", topic: "Basics", q: "What is a copy constructor?", opts: ["A constructor that makes the class final", "A constructor that creates a new object as a copy of another", "A constructor with no arguments", "A constructor for static classes"], ans: 1, exp: "A copy constructor takes an object of the same class as parameter and creates a new object with the same field values — a way to implement cloning." },
  { id: "oop58", diff: "easy", topic: "Basics", q: "Can we override static methods in Java?", opts: ["Yes", "No — static methods belong to the class, not instances", "Yes, but only in final classes", "Yes, with the @Override annotation"], ans: 1, exp: "Static methods cannot be overridden — they can be re-declared (method hiding), but the call is resolved at compile time based on the reference type, not runtime type." },
  { id: "oop59", diff: "easy", topic: "Basics", q: "What is the 'final' keyword when applied to a variable?", opts: ["Makes it static", "Makes it a constant — its value cannot be changed after initialisation", "Makes it abstract", "Makes it transient"], ans: 1, exp: "A 'final' variable is a constant. For primitives, the value can't change. For references, the reference can't change (though the object's state can, unless it's immutable)." },
  { id: "oop60", diff: "easy", topic: "Interface", q: "What is a functional interface?", opts: ["An interface with multiple methods", "An interface with exactly one abstract method", "An interface that extends Runnable", "An interface with only static methods"], ans: 1, exp: "A functional interface has exactly one abstract method (SAM — Single Abstract Method). Used as the basis for lambda expressions. Annotated with @FunctionalInterface (optional but recommended)." },
  { id: "oop61", diff: "easy", topic: "Basics", q: "What does JVM stand for?", opts: ["Java Variable Machine", "Java Virtual Machine", "Java Version Manager", "Java Visual Modifier"], ans: 1, exp: "JVM (Java Virtual Machine) executes Java bytecode. It provides platform independence — the same .class file runs on any OS with a JVM implementation." },
  { id: "oop62", diff: "easy", topic: "Basics", q: "What is the purpose of the 'hashCode()' method?", opts: ["Compare two objects", "Returns an integer hash for use in hash-based collections (HashMap, HashSet)", "Converts object to String", "Creates a copy of object"], ans: 1, exp: "hashCode() returns an integer representing the object, used to bucket it in hash tables. The contract: equal objects must have equal hash codes. Override hashCode() whenever you override equals()." },
  { id: "oop63", diff: "easy", topic: "Polymorphism", q: "What is dynamic method dispatch?", opts: ["Calling static methods dynamically", "The mechanism by which a call to an overridden method is resolved at runtime based on actual object type", "Calling interface methods", "Method overloading resolution"], ans: 1, exp: "Dynamic method dispatch (virtual method invocation): when a superclass reference holds a subclass object, the subclass's overridden method is called at runtime. Core of runtime polymorphism." },
  { id: "oop64", diff: "easy", topic: "Basics", q: "What is the 'protected' access modifier?", opts: ["Accessible only within class", "Accessible within same package and subclasses", "Accessible everywhere", "Accessible only through interfaces"], ans: 1, exp: "'protected' allows access within the same package and in subclasses (even in different packages). Useful for methods meant to be used/overridden by subclasses." },
  { id: "oop65", diff: "easy", topic: "Interface", q: "What is a marker interface?", opts: ["An interface with one method", "An interface with only constants", "An interface with no methods or fields — used to mark/tag a class", "A deprecated interface type"], ans: 2, exp: "Marker interfaces (Serializable, Cloneable, Remote) have no methods — they tag/mark a class, allowing the JVM or frameworks to identify and treat them specially." },
  { id: "oop66", diff: "easy", topic: "Basics", q: "What is the difference between a class and an object?", opts: ["No difference", "Class is an instance; object is a template", "Class is a blueprint; object is an instance of that blueprint", "Class is runtime; object is compile-time"], ans: 2, exp: "Class = design blueprint (exists once in memory as a type). Object = concrete instance (can have many) created from the blueprint with its own state." },
  { id: "oop67", diff: "easy", topic: "Basics", q: "What happens when you don't define any constructor in Java?", opts: ["Compile error", "The class cannot be used", "Java provides a default no-arg constructor", "A runtime exception is thrown"], ans: 2, exp: "The Java compiler automatically inserts a public no-arg default constructor that calls super(). This is removed once you define any constructor yourself." },
  { id: "oop68", diff: "easy", topic: "Encapsulation", q: "What is the benefit of encapsulation?", opts: ["Increases execution speed", "Prevents code reuse", "Protects data integrity and hides implementation details", "Allows multiple inheritance"], ans: 2, exp: "Encapsulation bundles data and methods, prevents direct external access to internal state, enforces invariants via validation in setters, and allows implementation changes without breaking callers." },
  { id: "oop69", diff: "easy", topic: "Inheritance", q: "What is the IS-A relationship?", opts: ["Composition relationship", "Inheritance relationship — a subclass IS-A type of its superclass", "Association relationship", "Aggregation relationship"], ans: 1, exp: "IS-A represents inheritance: Dog IS-AN Animal. Test: can you substitute a Dog wherever an Animal is expected? If yes, IS-A is appropriate. This is the Liskov Substitution Principle foundation." },
  { id: "oop70", diff: "easy", topic: "Basics", q: "What is the HAS-A relationship?", opts: ["Inheritance relationship", "Composition or aggregation — one class contains a reference to another", "Interface implementation", "Static relationship"], ans: 1, exp: "HAS-A represents composition/aggregation: Car HAS-AN Engine. Prefer composition over inheritance when the relationship is 'has' rather than 'is'. More flexible and less coupled." },
  { id: "oop71", diff: "medium", topic: "Polymorphism", q: "What is covariant return type in method overriding?", opts: ["Returning a broader type", "Returning the same type always", "Returning a subtype of the return type declared in the overridden method", "Returning void always"], ans: 2, exp: "Since Java 5, an overriding method can return a subtype of the original return type. e.g., parent returns Animal, child can return Dog (a subtype). Makes overriding more flexible." },
  { id: "oop72", diff: "medium", topic: "Polymorphism", q: "Can we override the equals() and hashCode() methods?", opts: ["No, they are final", "Yes, and it's often required for correct behaviour in collections", "Only equals() can be overridden", "Only hashCode() can be overridden"], ans: 1, exp: "Yes — and both must be overridden together (contract). If equals() returns true for two objects, their hashCode() must be equal, otherwise HashMap/HashSet will behave incorrectly." },
  { id: "oop73", diff: "medium", topic: "Inheritance", q: "What is the diamond problem in multiple inheritance?", opts: ["A compiler error in single inheritance", "Ambiguity when a class inherits the same method from two parents that both inherited from a common ancestor", "A NullPointerException pattern", "A memory leak pattern"], ans: 1, exp: "If D extends B and C, and B and C both override method from A, which version does D inherit? Java avoids this for classes (single inheritance). Interfaces handle it with default method resolution rules." },
  { id: "oop74", diff: "medium", topic: "Interface", q: "What is a default method in an interface (Java 8+)?", opts: ["A method that does nothing", "A method with a body in an interface, providing a default implementation", "A private method", "An overridable abstract method"], ans: 1, exp: "Java 8 'default' methods have an implementation in the interface itself. Implementing classes inherit the default implementation unless they override it. Enables adding methods to interfaces without breaking existing implementations." },
  { id: "oop75", diff: "medium", topic: "Interface", q: "If a class implements two interfaces that both have the same default method, what must the class do?", opts: ["Nothing — Java picks automatically", "Override the method to resolve the ambiguity", "Implement only one interface", "Throw a compile error at runtime"], ans: 1, exp: "A compile-time error occurs if a class inherits conflicting default methods without overriding. The class MUST override the method to resolve ambiguity, optionally calling Interface.super.method()." },
  { id: "oop76", diff: "medium", topic: "Abstraction", q: "Can an abstract class have a constructor?", opts: ["No", "Yes, called by subclass constructors via super()", "Only if it has no abstract methods", "Only private constructors"], ans: 1, exp: "Abstract classes CAN have constructors. They are called when a subclass is instantiated (via super()). Useful for initialising common fields in the abstract class." },
  { id: "oop77", diff: "medium", topic: "Abstraction", q: "What happens if a subclass does not implement all abstract methods of the parent?", opts: ["Runtime exception", "Compile-time error unless the subclass is also declared abstract", "Nothing — they are skipped", "The class uses default implementations"], ans: 1, exp: "If a concrete class doesn't implement all abstract methods, the compiler throws an error. If it's declared abstract itself, it can defer implementation to further subclasses." },
  { id: "oop78", diff: "medium", topic: "Basics", q: "What is the contract between equals() and hashCode()?", opts: ["No contract exists", "If two objects are equal (equals() = true), they must have the same hashCode", "If two objects have the same hashCode, they must be equal", "hashCode() must always return 0"], ans: 1, exp: "Java contract: equals() = true → same hashCode(). Reverse is NOT required (hash collision is allowed). Violating this breaks HashMap, HashSet, and any hash-based collection." },
  { id: "oop79", diff: "medium", topic: "Design", q: "What is the Singleton design pattern?", opts: ["A class with only static methods", "A pattern ensuring only one instance of a class exists", "A pattern creating many objects", "An inheritance pattern"], ans: 1, exp: "Singleton ensures a class has exactly one instance with global access. Implemented via private constructor, static instance field, and a static getInstance() method. Thread-safety requires synchronisation or the initialise-on-demand holder pattern." },
  { id: "oop80", diff: "medium", topic: "Design", q: "What pattern does the following describe: An abstract creator class with a method that subclasses override to create objects?", opts: ["Singleton", "Factory Method", "Observer", "Strategy"], ans: 1, exp: "Factory Method: defines an interface for creating an object but lets subclasses decide which class to instantiate. Promotes loose coupling between creation logic and usage." },
  { id: "oop81", diff: "medium", topic: "Polymorphism", q: "What is the output of calling an overridden method via a superclass reference? Animal a = new Dog(); a.sound();", opts: ["Always calls Animal's sound()", "Always calls Dog's sound()", "Compile error", "Depends on the cast"], ans: 1, exp: "Runtime polymorphism: the actual object type (Dog) determines which method runs, not the reference type (Animal). This is the power of dynamic dispatch." },
  { id: "oop82", diff: "medium", topic: "Basics", q: "What is object cloning in Java?", opts: ["Creating a new class", "Creating a copy of an existing object", "Converting object to String", "Serializing an object"], ans: 1, exp: "Object cloning creates a copy of an object. Implement Cloneable (marker interface) and override clone(). Shallow clone copies field values; deep clone also clones referenced objects." },
  { id: "oop83", diff: "medium", topic: "Basics", q: "What is the difference between shallow copy and deep copy?", opts: ["No difference", "Shallow copy copies primitive fields; deep copy copies nothing", "Shallow copy copies references (shared objects); deep copy copies the entire object graph recursively", "Deep copy copies only primitives"], ans: 2, exp: "Shallow copy: a new object with the same field values — reference fields point to the SAME nested objects. Deep copy: a new object where reference fields point to NEW copies of the nested objects." },
  { id: "oop84", diff: "medium", topic: "Design", q: "What is the purpose of the Builder pattern?", opts: ["Build inheritance hierarchies", "Construct complex objects step by step, separating construction from representation", "Build interfaces dynamically", "Create singleton instances"], ans: 1, exp: "Builder separates construction of a complex object from its representation. Useful when an object has many optional parameters (avoids telescoping constructors). Used in StringBuilder, Lombok @Builder, AlertDialog.Builder." },
  { id: "oop85", diff: "medium", topic: "Inheritance", q: "What is method hiding in Java?", opts: ["Making a method private", "Defining a static method in a subclass with the same signature as a static method in the parent — resolved by reference type", "Overriding an instance method", "Preventing method access from other packages"], ans: 1, exp: "When a subclass defines a static method with the same signature as a parent's static method, it HIDES (not overrides) it. The call is resolved at compile time based on reference type, not runtime type." },
  { id: "oop86", diff: "medium", topic: "Basics", q: "What is the 'transient' keyword in Java?", opts: ["Makes a field static", "Prevents a field from being serialized", "Makes a field volatile", "Makes a field final"], ans: 1, exp: "'transient' fields are excluded from serialization. When an object is serialized to a stream, transient fields are skipped and restored to default values upon deserialization." },
  { id: "oop87", diff: "medium", topic: "Basics", q: "What is the 'volatile' keyword?", opts: ["Makes a variable constant", "Ensures all threads see the latest value of a variable (prevents caching in CPU registers/L1 cache)", "Makes a field transient", "Makes a method synchronized"], ans: 1, exp: "'volatile' ensures visibility: reads/writes of the variable go directly to main memory, not CPU cache. Doesn't guarantee atomicity (use AtomicInteger or synchronized for that)." },
  { id: "oop88", diff: "medium", topic: "Interface", q: "Can interfaces have static methods (Java 8+)?", opts: ["No", "Yes, and they cannot be overridden — called via InterfaceName.method()", "Yes, and they are inherited", "Yes, but only abstract static"], ans: 1, exp: "Java 8 allows 'static' methods in interfaces. Unlike default methods, they are NOT inherited by implementing classes and must be called via the interface name." },
  { id: "oop89", diff: "medium", topic: "Interface", q: "Can interfaces have private methods (Java 9+)?", opts: ["No", "Yes — to share code between default methods without exposing to implementing classes", "Yes, but only abstract", "Only in functional interfaces"], ans: 1, exp: "Java 9 introduced private methods in interfaces to allow code reuse between default methods, without exposing the helper logic to implementing classes." },
  { id: "oop90", diff: "medium", topic: "Design", q: "What is the Observer (Publisher-Subscriber) pattern?", opts: ["One object creates many", "An object (subject) maintains a list of dependents (observers) and notifies them automatically of state changes", "One object delegates to another", "Hiding implementation behind interface"], ans: 1, exp: "Observer: Subject maintains a list of Observer objects and calls their update() when state changes. Foundation of event systems, MVC, reactive programming, and Java's EventListener." },
  { id: "oop91", diff: "medium", topic: "Generics", q: "What are Java generics?", opts: ["Runtime type information", "A mechanism for parameterizing types (classes, interfaces, methods) to ensure type safety at compile time", "Dynamic casting", "Primitive type boxing"], ans: 1, exp: "Generics allow writing classes/methods that work with any type while maintaining compile-time type safety. e.g., List<String> ensures only Strings are added, eliminating casts and ClassCastExceptions." },
  { id: "oop92", diff: "medium", topic: "Generics", q: "What is type erasure in Java generics?", opts: ["Removing all code at runtime", "Generic type parameters are removed (erased) at compile time and replaced with Object or bounds — generics exist only at compile time", "Converting generics to primitives", "Deleting unused generic classes"], ans: 1, exp: "Type erasure: the compiler removes all generic type information before generating bytecode. List<String> and List<Integer> become just List at runtime. This maintains backward compatibility." },
  { id: "oop93", diff: "medium", topic: "Generics", q: "What is a bounded type parameter? Example: <T extends Comparable<T>>", opts: ["A type that must be a primitive", "A type parameter restricted to a class or its subclasses", "A type that cannot extend anything", "A fixed type parameter"], ans: 1, exp: "<T extends Comparable<T>> means T must implement Comparable. Upper bounded wildcard <? extends Number> accepts Number and subclasses. Lower bounded <? super Integer> accepts Integer and supertypes." },
  { id: "oop94", diff: "medium", topic: "Basics", q: "What is the difference between String, StringBuilder, and StringBuffer?", opts: ["No difference", "String is immutable; StringBuilder is mutable and not thread-safe; StringBuffer is mutable and thread-safe", "String is mutable; StringBuilder is immutable", "StringBuffer is faster than StringBuilder"], ans: 1, exp: "String: immutable (creates new object on modification). StringBuilder: mutable, not thread-safe, faster. StringBuffer: mutable, thread-safe (synchronized methods), slightly slower. Use StringBuilder in single-threaded code." },
  { id: "oop95", diff: "medium", topic: "Basics", q: "Why is String immutable in Java?", opts: ["Compiler limitation", "Security (passwords), String pool efficiency, thread safety, and hashCode caching", "Memory limitation", "Simplicity"], ans: 1, exp: "Immutability enables: (1) String pool sharing (interning), (2) thread safety, (3) security (credentials can't be changed after passing), (4) cached hashCode. A mutable String used as HashMap key would corrupt the map on modification." },
  { id: "oop96", diff: "medium", topic: "Basics", q: "What is the String pool (String intern pool)?", opts: ["A buffer for string output", "An area in the heap where String literals are cached and shared", "A sorted collection of Strings", "A thread-safe String queue"], ans: 1, exp: "String literals like 'hello' are stored in the String pool. If the same literal is used again, the same object is returned rather than creating a new one. This saves memory. String.intern() adds a string to the pool." },
  { id: "oop97", diff: "medium", topic: "Exception", q: "What is the difference between checked and unchecked exceptions?", opts: ["No difference", "Checked exceptions must be declared or handled at compile time; unchecked extend RuntimeException and don't require explicit handling", "Unchecked exceptions must be caught; checked don't", "Checked exceptions crash the JVM"], ans: 1, exp: "Checked (IOException, SQLException): compiler forces you to handle or declare them (throws). Unchecked (RuntimeException subclasses: NullPointerException, ArrayIndexOutOfBoundsException): no compile-time enforcement." },
  { id: "oop98", diff: "medium", topic: "Exception", q: "What is the difference between 'throw' and 'throws'?", opts: ["No difference", "'throw' actually throws an exception object; 'throws' declares that a method might throw exceptions", "'throws' throws; 'throw' declares", "Both are the same keyword"], ans: 1, exp: "'throw' is used inside a method body to actually throw an exception: throw new IOException(). 'throws' is in the method signature to declare which checked exceptions a method can throw." },
  { id: "oop99", diff: "medium", topic: "Exception", q: "Can we have a try block without a catch block?", opts: ["No, always need catch", "Yes, with a finally block", "Yes, always", "No, try needs both catch and finally"], ans: 1, exp: "try-finally is valid without catch. Also try-with-resources doesn't need explicit catch. You need at least one of: catch block, finally block, or both." },
  { id: "oop100", diff: "medium", topic: "Exception", q: "What does the finally block guarantee?", opts: ["It runs only on exception", "It runs only on normal execution", "It always runs regardless of whether an exception occurred or was caught (except System.exit())", "It runs before try"], ans: 2, exp: "finally always executes (even if return is hit in try/catch), making it ideal for cleanup (closing streams, DB connections). Only System.exit() or JVM crash can skip finally." },
  { id: "oop101", diff: "medium", topic: "Collections", q: "What is the difference between ArrayList and LinkedList?", opts: ["No difference", "ArrayList uses array (fast random access, slow insert/delete in middle); LinkedList uses doubly linked list (fast insert/delete, slow random access)", "LinkedList uses array; ArrayList uses linked list", "ArrayList is thread-safe; LinkedList is not"], ans: 1, exp: "ArrayList: O(1) get, O(n) add/remove in middle (shifting). LinkedList: O(n) get (traversal), O(1) add/remove at head/tail. Use ArrayList for read-heavy; LinkedList for frequent insertions at ends." },
  { id: "oop102", diff: "medium", topic: "Collections", q: "What is the difference between HashMap and Hashtable?", opts: ["No difference", "HashMap: not synchronized, allows one null key; Hashtable: synchronized, no null keys/values, legacy", "Hashtable is faster", "HashMap is sorted"], ans: 1, exp: "HashMap: not thread-safe, allows one null key and multiple null values, faster. Hashtable: thread-safe (synchronized), no nulls, legacy. Prefer ConcurrentHashMap over Hashtable for thread safety with better performance." },
  { id: "oop103", diff: "medium", topic: "Collections", q: "What is the difference between HashSet and TreeSet?", opts: ["No difference", "HashSet: unordered, O(1) operations; TreeSet: sorted (natural/Comparator order), O(log n) operations, implements NavigableSet", "TreeSet is faster", "HashSet is sorted"], ans: 1, exp: "HashSet uses HashMap internally — no order guarantee, O(1) average. TreeSet uses Red-Black tree — maintains sorted order, O(log n). Use TreeSet when you need sorted iteration." },
  { id: "oop104", diff: "medium", topic: "Basics", q: "What is the Comparable interface?", opts: ["For comparing objects with ==", "A functional interface with compareTo() that defines the natural ordering of a class's instances", "An interface for sorting arrays only", "For comparing class types"], ans: 1, exp: "Comparable<T> has compareTo(T o): returns negative (this < o), 0 (equal), positive (this > o). Defines the natural ordering. Used by Collections.sort() and TreeSet without a separate Comparator." },
  { id: "oop105", diff: "medium", topic: "Basics", q: "What is the Comparator interface?", opts: ["Same as Comparable", "A functional interface that defines external/custom ordering logic, separate from the class being compared", "An interface for natural ordering", "Used only with arrays"], ans: 1, exp: "Comparator<T> has compare(T o1, T o2). Provides external/alternative ordering without modifying the class. Multiple Comparators can exist for the same class (by name, by age, etc.). Used in Collections.sort(list, comparator)." },
  { id: "oop106", diff: "medium", topic: "Basics", q: "What is a lambda expression?", opts: ["A new class type", "A concise, anonymous function syntax (()->), primarily used to implement functional interfaces", "A static method reference", "A recursive method"], ans: 1, exp: "Lambdas: (params) -> expression or (params) -> {body}. They implement functional interfaces inline. e.g., list.sort((a,b) -> a.compareTo(b)). They close over effectively-final variables." },
  { id: "oop107", diff: "medium", topic: "Basics", q: "What is a Stream in Java (java.util.stream)?", opts: ["An I/O byte stream", "A pipeline of operations on a data source (collections, arrays) for functional-style processing", "A thread pool", "A database connection"], ans: 1, exp: "Java 8 Streams support declarative, functional-style data processing: filter, map, reduce, collect. Streams are lazy (processed only when terminal operation is called) and can be parallel." },
  { id: "oop108", diff: "medium", topic: "Basics", q: "What is the difference between intermediate and terminal operations in Streams?", opts: ["No difference", "Intermediate operations (filter, map) return a Stream and are lazy; terminal operations (collect, forEach, count) trigger processing and return a result", "Terminal operations return a Stream", "Intermediate operations are eager"], ans: 1, exp: "Intermediate: lazy, return Stream, chained (filter(), map(), sorted()). Terminal: trigger the pipeline, return a result or side effect (collect(), forEach(), reduce(), count(), findFirst())." },
  { id: "oop109", diff: "medium", topic: "Design", q: "What is the Decorator pattern?", opts: ["Adding methods to a subclass", "Wrapping an object to add behaviour dynamically without subclassing", "Creating objects via factory", "Hiding object creation"], ans: 1, exp: "Decorator: wraps an object with another object implementing the same interface, adding functionality. Java I/O streams are the classic example: new BufferedReader(new FileReader('file'))." },
  { id: "oop110", diff: "medium", topic: "Design", q: "What is the Strategy pattern?", opts: ["A pattern for creating objects", "Defining a family of algorithms, encapsulating each, and making them interchangeable at runtime", "A pattern for organizing inheritance", "Observer notification pattern"], ans: 1, exp: "Strategy: encapsulate interchangeable behaviours (algorithms) behind a common interface. The context delegates to the strategy at runtime. e.g., different sorting algorithms, payment methods, compression algorithms." },
  { id: "oop111", diff: "medium", topic: "Inheritance", q: "What is the Liskov Substitution Principle (LSP)?", opts: ["A subclass can replace its superclass without altering correctness of the program", "A class must implement all interfaces", "Favour composition over inheritance", "Program to interfaces, not implementations"], ans: 0, exp: "LSP (L in SOLID): objects of a superclass must be replaceable with objects of any subclass without breaking the program. If class B extends A, anywhere A is used, B should work correctly without the caller knowing." },
  { id: "oop112", diff: "medium", topic: "Design", q: "What does SOLID stand for?", opts: ["5 Java keywords", "Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion", "5 OOP pillars", "Standard Object Language Interface Design"], ans: 1, exp: "SOLID: 5 principles of OOP design. S=Single Responsibility. O=Open for extension/Closed for modification. L=Liskov Substitution. I=Interface Segregation. D=Dependency Inversion." },
  { id: "oop113", diff: "medium", topic: "Design", q: "What is Dependency Injection (DI)?", opts: ["Injecting code at runtime", "Providing dependencies (objects a class needs) from outside rather than the class creating them — enables loose coupling and testability", "A design pattern for interfaces", "Creating objects dynamically"], ans: 1, exp: "DI: instead of class A creating class B internally (new B()), B is provided to A externally (via constructor, setter, or field injection). Used in Spring, testing with mocks. Implements Dependency Inversion Principle." },
  { id: "oop114", diff: "medium", topic: "Basics", q: "What is the purpose of the 'instanceof' pattern matching (Java 16+)?", opts: ["Checks if null", "Pattern matching: instanceof checks type AND extracts a typed variable in one expression, eliminating explicit cast", "Creates new instances", "Checks method signatures"], ans: 1, exp: "Java 16+: if (obj instanceof String s) { s.length(); } — checks type and binds the variable 's' of type String in scope. Eliminates the boilerplate cast after instanceof." },
  { id: "oop115", diff: "medium", topic: "Basics", q: "What is a record class (Java 16+)?", opts: ["A legacy class type", "A compact, immutable data carrier class with auto-generated constructor, getters, equals, hashCode, toString", "A mutable POJO class", "An abstract data type"], ans: 1, exp: "record Person(String name, int age) {} auto-generates: constructor, accessors (name(), age()), equals(), hashCode(), toString(). Designed for immutable data transfer objects (DTOs). Fields are final by default." },
  { id: "oop116", diff: "medium", topic: "Basics", q: "What is a sealed class (Java 17+)?", opts: ["A final class", "A class that restricts which classes can extend it using 'permits' clause", "A class with no constructor", "A private class"], ans: 1, exp: "sealed class Shape permits Circle, Rectangle {} — only Circle and Rectangle can extend Shape. Enables exhaustive pattern matching on a fixed type hierarchy." },
  { id: "oop117", diff: "medium", topic: "Basics", q: "What is object serialization?", opts: ["Converting object to String", "Converting an object's state to a byte stream for storage or transmission", "Sorting objects", "Compressing objects"], ans: 1, exp: "Serialization (implementing Serializable): converts object state to a byte stream. Deserialization reconstructs the object. Used in file storage, network transmission, RMI." },
  { id: "oop118", diff: "medium", topic: "Design", q: "What is the Template Method pattern?", opts: ["Creating object templates", "Defining the skeleton of an algorithm in a superclass, deferring some steps to subclasses", "Creating interface templates", "Builder pattern variant"], ans: 1, exp: "Template Method: an abstract class defines the algorithm's skeleton in a final method, calling abstract hook methods. Subclasses override hooks to customise steps without changing the overall algorithm structure." },
  { id: "oop119", diff: "medium", topic: "Basics", q: "What is an enum in Java OOP terms?", opts: ["A primitive type", "A special class representing a fixed set of constants, with type safety and ability to have fields and methods", "An interface type", "A generic type"], ans: 1, exp: "Java enums are full classes: they can have fields, methods, constructors, and implement interfaces. Each constant (NORTH, SOUTH) is a static final instance of the enum class." },
  { id: "oop120", diff: "medium", topic: "Basics", q: "What is the purpose of the @Override annotation?", opts: ["Creates a new method", "Signals the compiler to verify that the method actually overrides a superclass method — catches typos/signature mismatches at compile time", "Makes a method final", "Makes a method abstract"], ans: 1, exp: "@Override is checked at compile time. If the annotated method doesn't override (due to typo, wrong signature), the compiler gives an error. Best practice to always annotate overriding methods." },
  { id: "oop121", diff: "medium", topic: "Collections", q: "What is the difference between fail-fast and fail-safe iterators?", opts: ["No difference", "Fail-fast throws ConcurrentModificationException if the collection is modified during iteration; fail-safe iterates over a copy and doesn't throw", "Fail-safe is for arrays only", "Fail-fast uses snapshots"], ans: 1, exp: "Fail-fast (ArrayList, HashMap iterators): detect structural modification via modCount, throw ConcurrentModificationException. Fail-safe (CopyOnWriteArrayList, ConcurrentHashMap): work on a snapshot/copy, no exception." },
  { id: "oop122", diff: "medium", topic: "Basics", q: "What is inner class? How does it differ from a static nested class?", opts: ["No difference", "Inner class is non-static and has access to enclosing instance; static nested class has no implicit outer instance reference", "Static nested class is inner; inner class is outer", "Inner classes are only anonymous"], ans: 1, exp: "Inner class: needs an outer instance to be created, can access outer class members. Static nested class: no outer instance needed, can only access outer class's static members." },
  { id: "oop123", diff: "medium", topic: "Basics", q: "What is an anonymous inner class?", opts: ["A class with no fields", "A one-time-use class defined and instantiated in a single expression, implementing an interface or extending a class", "A class in another package", "A lambda expression"], ans: 1, exp: "Anonymous inner class: new Comparator<String>() { public int compare(String a, String b) { return a.compareTo(b); } }. Defined and instantiated at once. Often replaced by lambdas in Java 8+." },
  { id: "oop124", diff: "medium", topic: "Design", q: "What is the Adapter pattern?", opts: ["Adapting a class to a new OOP language", "Converting the interface of a class into another interface clients expect — bridges incompatible interfaces", "Adapting to a new database", "A parallel programming pattern"], ans: 1, exp: "Adapter: wraps an existing class with a new interface. Like a power plug adapter — the existing Adaptee class has the functionality but wrong interface; Adapter makes it compatible." },
  { id: "oop125", diff: "medium", topic: "Basics", q: "What is the 'var' keyword (Java 10+)?", opts: ["Declares a variable with no type", "Local variable type inference — compiler infers the type from the right-hand side", "Makes a variable variable (mutable)", "Declares a volatile variable"], ans: 1, exp: "var x = new ArrayList<String>() — the compiler infers x is ArrayList<String>. Only for local variables. The type is still statically known at compile time — var is NOT dynamic typing." },
  { id: "oop126", diff: "medium", topic: "Basics", q: "What are Optional<T> and why are they used?", opts: ["A type that can hold any type", "A container that may or may not contain a non-null value — used to avoid NullPointerException and make optional return values explicit", "A generic collection", "A thread-safe wrapper"], ans: 1, exp: "Optional<T>: either contains a value (isPresent()=true) or is empty. Forces callers to handle the null case explicitly: optional.orElse('default'), optional.ifPresent(val->...). Expressive alternative to returning null." },
  { id: "oop127", diff: "medium", topic: "Design", q: "What is the Proxy pattern?", opts: ["Hiding implementation", "Providing a surrogate or placeholder for another object to control access, add lazy initialisation, logging, or remote access", "Creating multiple objects", "Sorting objects by proxy"], ans: 1, exp: "Proxy: same interface as the real object, delegating calls while adding: access control, lazy initialisation, caching, logging, or remote access. Java's java.lang.reflect.Proxy provides dynamic proxies at runtime." },
  { id: "oop128", diff: "medium", topic: "Basics", q: "What is method reference in Java 8+?", opts: ["A pointer to a method's memory address", "A shorthand notation for a lambda that simply calls an existing method: ClassName::methodName", "A reference to a constructor", "Referencing methods from other classes only"], ans: 1, exp: "Method references: shorthand for lambdas. Types: (1) Static: Math::abs, (2) Instance of specific type: String::length, (3) Instance of particular object: myObj::method, (4) Constructor: ArrayList::new." },
  { id: "oop129", diff: "medium", topic: "Generics", q: "What is the difference between <? extends T> and <? super T>?", opts: ["No difference", "<? extends T> is upper-bounded (for reading/producers); <? super T> is lower-bounded (for writing/consumers) — PECS principle", "<? super T> is for reading", "Both are upper-bounded"], ans: 1, exp: "PECS (Producer Extends, Consumer Super): use <? extends T> to READ from a structure (producer), <? super T> to WRITE to it (consumer). Collections.copy(List<? super T> dest, List<? extends T> src) demonstrates this." },
  { id: "oop130", diff: "medium", topic: "Basics", q: "What is the difference between composition and aggregation?", opts: ["No difference", "Composition: strong ownership — child cannot exist without parent (lifecycle tied). Aggregation: weak relationship — child can exist independently", "Aggregation is stronger", "Composition is weaker"], ans: 1, exp: "Composition: House HAS-A Room — the Room's lifecycle is tied to the House (destroyed with it). Aggregation: University HAS-AN Professor — the Professor exists independently." },
  { id: "oop131", diff: "medium", topic: "Design", q: "What is the Facade pattern?", opts: ["Same as Adapter", "Provides a simplified unified interface to a complex subsystem — clients interact with the facade rather than the complex internals", "A pattern for managing dependencies", "Hiding abstract classes from clients"], ans: 1, exp: "Facade: HomeTheater.watchMovie() internally calls: amplifier.on(), dvdPlayer.load(), projector.widescreen(), lights.dim(). Clients call one method instead of coordinating many. Doesn't prevent access to subsystem — just simplifies the common case." },
  { id: "oop132", diff: "medium", topic: "Design", q: "What is the Composite pattern?", opts: ["Combining two classes", "Treating individual objects and compositions of objects uniformly — tree structures where leaf and composite implement the same interface", "Database composition", "Thread composition"], ans: 1, exp: "Composite: Component interface implemented by Leaf (no children) and Composite (has children, delegates operations). Used in file systems (File/Folder), GUI (Widget/Panel), org charts. Client code treats both leaves and composites identically." },
  { id: "oop133", diff: "medium", topic: "Basics", q: "What is the difference between association, aggregation, and composition?", opts: ["They are the same", "Association: general 'uses' relationship. Aggregation: HAS-A with independent lifecycle. Composition: HAS-A with dependent lifecycle (child dies with parent)", "Composition is weakest", "Aggregation implies inheritance"], ans: 1, exp: "Association: Teacher teaches Student (no ownership). Aggregation: Team HAS Players (Players exist independently). Composition: Human HAS-A Heart (Heart dies with Human). Increasing strength: association < aggregation < composition." },
  { id: "oop134", diff: "medium", topic: "Generics", q: "What is a raw type in Java and why is it dangerous?", opts: ["A primitive type", "Using a generic class without type parameters — bypasses compile-time type checking and can cause ClassCastException at runtime", "A type for raw data", "An unboxed wrapper type"], ans: 1, exp: "Raw type: List list = new ArrayList() (no <T>). Compiler allows inserting any type. At runtime, when you get and cast an element, ClassCastException can occur. Raw types exist for backward compatibility — avoid them in new code." },
  { id: "oop135", diff: "medium", topic: "Design", q: "What is the Command pattern?", opts: ["Commanding other objects", "Encapsulating a request as an object — enables parameterising requests, queuing, logging, and undo/redo operations", "A singleton variant", "Threading pattern"], ans: 1, exp: "Command: encapsulate a request as an object with execute()/undo() methods. Enables: queuing requests, logging, undo/redo stacks, transactional behaviour. GUI actions, database transactions, and job schedulers use this." },
  { id: "oop136", diff: "medium", topic: "Design", q: "What is the Chain of Responsibility pattern?", opts: ["Calling methods in a chain", "Passing a request along a chain of handlers — each handler decides to process or pass to the next", "Inheritance chain", "Observer notification chain"], ans: 1, exp: "CoR: decouple sender from receiver. Request travels through a chain of handlers; each either handles it or passes it on. Used in event handling (Java AWT/Swing), HTTP filters (Servlet Filter chain), logging frameworks." },
  { id: "oop137", diff: "medium", topic: "Design", q: "What is the Memento pattern?", opts: ["Memory management", "Capturing and externalising an object's internal state to restore it later — without violating encapsulation", "Caching pattern", "State machine pattern"], ans: 1, exp: "Memento: Originator creates a Memento (snapshot of state), stored by Caretaker. Originator can restore from Memento. Enables undo/redo without exposing internals." },
  { id: "oop138", diff: "medium", topic: "SOLID", q: "Explain the Open/Closed Principle.", opts: ["Classes must be open for all changes", "Software entities should be open for extension but closed for modification — add new behaviour by adding new code, not changing existing code", "Only use open source", "All methods must be overridable"], ans: 1, exp: "OCP: add functionality by extending (new subclasses, new implementations) rather than modifying existing tested code. Achieved via: interfaces, abstract classes, strategy pattern." },
  { id: "oop139", diff: "medium", topic: "SOLID", q: "Explain the Interface Segregation Principle (ISP).", opts: ["Use large interfaces", "Clients should not be forced to depend on interfaces they don't use — split large interfaces into smaller, more specific ones", "Interfaces should have 10+ methods", "All interfaces must be functional"], ans: 1, exp: "ISP: instead of one fat interface with 20 methods, have multiple focused interfaces. Implementing classes only depend on what they actually use." },
  { id: "oop140", diff: "medium", topic: "SOLID", q: "Explain the Dependency Inversion Principle (DIP).", opts: ["High-level modules depend on low-level modules", "High-level modules should not depend on low-level modules — both should depend on abstractions (interfaces/abstract classes)", "Avoid interfaces", "Only abstract classes allowed"], ans: 1, exp: "DIP: decouple high-level policy from low-level details. High-level: OrderProcessor. Low-level: EmailService, DatabaseLogger. Both should depend on: INotificationService, ILogger abstractions. Enables swapping implementations." },
  { id: "oop141", diff: "medium", topic: "Basics", q: "What is reflection in Java?", opts: ["Mirroring code", "The ability to inspect and manipulate classes, methods, and fields at runtime — even private members", "A design pattern", "Code generation"], ans: 1, exp: "Reflection (java.lang.reflect): inspect Class objects, list methods/fields, invoke methods by name, create instances dynamically. Used in frameworks (Spring, JUnit, Jackson). Trade-offs: loses compile-time safety, slower than direct calls." },
  { id: "oop142", diff: "medium", topic: "Basics", q: "What is dynamic proxy in Java?", opts: ["A cached object", "A proxy object created at runtime using java.lang.reflect.Proxy that implements specified interfaces — all method calls are dispatched to an InvocationHandler", "A design pattern", "A serialization technique"], ans: 1, exp: "Dynamic proxy: Proxy.newProxyInstance(loader, interfaces[], handler). The handler's invoke() intercepts all calls. Used in Spring AOP (transaction, security, logging), RPC stubs, mocking frameworks (Mockito)." },
  { id: "oop143", diff: "medium", topic: "Generics", q: "What is heap pollution in Java generics?", opts: ["Memory leak", "A situation where a variable of parameterized type refers to an object that is not of that type — caused by raw types or unchecked casts, leading to ClassCastException later", "GC fragmentation", "Stack overflow from generics"], ans: 1, exp: "Heap pollution: List<String> list = (List<String>) rawList; — inserts the wrong type silently. The ClassCastException occurs later when you retrieve and use the element, making the bug hard to trace." },
  { id: "oop144", diff: "medium", topic: "Design", q: "What is the difference between inheritance and composition, and why prefer composition?", opts: ["Inheritance is always better", "Inheritance couples subclass to superclass (brittle base class problem); composition is more flexible — change behaviour at runtime, no compile-time binding, easier testing", "Composition is always wrong", "They are equivalent"], ans: 1, exp: "'Prefer composition over inheritance' (GoF): inheritance exposes superclass internals (fragile), breaks encapsulation, is static. Composition: flexible (swap implementations at runtime), testable (mock dependencies)." },
  { id: "oop145", diff: "medium", topic: "Basics", q: "What is Inversion of Control (IoC)?", opts: ["Inverting loop control", "A principle where the control of object creation and lifecycle is given to a container/framework rather than the application code", "Reversing inheritance", "Inverting method calls"], ans: 1, exp: "IoC: instead of your code calling the framework, the framework calls your code (Hollywood Principle). Spring IoC container creates and wires beans. Dependency Injection is one implementation of IoC." },
  { id: "oop146", diff: "medium", topic: "Basics", q: "What is a covariant vs contravariant type system?", opts: ["Not relevant to Java", "Covariant: if B extends A, then String[] IS-A Object[] (arrays are covariant). Generics are invariant: List<String> is NOT a subtype of List<Object>. Wildcards provide use-site variance.", "Java is fully covariant", "Java is fully contravariant"], ans: 1, exp: "Java arrays are covariant (String[] IS-A Object[]) — can cause ArrayStoreException. Java generics are INVARIANT (List<String> is NOT a subtype of List<Object>). Wildcards provide use-site variance: <? extends T> (covariant), <? super T> (contravariant)." },
  { id: "oop147", diff: "medium", topic: "Basics", q: "What is the difference between early binding and late binding?", opts: ["No difference", "Early/static binding: method resolved at compile time (overloading, static methods). Late/dynamic binding: method resolved at runtime (overriding) based on actual object type", "Late binding is for constructors", "Early binding is for interfaces"], ans: 1, exp: "Early binding: compiler knows exactly which method to call (overloaded methods, static methods, final methods, private methods). Late binding: JVM determines at runtime which method to call via vtable lookup — enables polymorphism." },
  { id: "oop148", diff: "medium", topic: "Design", q: "What is the Null Object pattern?", opts: ["Using null safely", "Providing a default object with do-nothing (neutral) behaviour to avoid null checks — implements the same interface as real objects", "Creating null pointers safely", "A pattern to detect null"], ans: 1, exp: "Null Object: instead of returning null, return a NullCustomer object that implements Customer with empty/no-op implementations. Eliminates null checks in client code. Optional<T> is a modern approach." },
  { id: "oop149", diff: "medium", topic: "Basics", q: "What is object interning?", opts: ["Converting objects to primitives", "Caching and reusing objects with the same value — String.intern(), Integer cache (-128 to 127) are examples", "Serializing objects", "Compressing objects"], ans: 1, exp: "Interning: maintaining a pool of canonical objects. Requesting the same value returns the cached instance. String.intern() adds to pool. Integer.valueOf(127) returns cached Integer. Saves memory." },
  { id: "oop150", diff: "medium", topic: "Design", q: "What is the Iterator pattern and how does Java implement it?", opts: ["Iterating over arrays only", "Providing a way to sequentially access elements of a collection without exposing its underlying representation — Java: Iterable<T> + Iterator<T> interfaces", "A sorting algorithm", "A design pattern for arrays"], ans: 1, exp: "Iterator: Collection implements Iterable<T> (has iterator()). Iterator<T> has hasNext(), next(), remove(). for-each loop uses Iterable. The pattern decouples traversal from the collection." },
  { id: "oop151", diff: "medium", topic: "Design", q: "What is the State pattern?", opts: ["Managing static fields", "Allowing an object to alter its behaviour when its internal state changes — the object will appear to change its class", "Thread state management", "Exception state management"], ans: 1, exp: "State: object behaviour changes with state. Instead of large if/switch on state, each state is a class implementing a State interface. Context delegates to current state object. Used in vending machines, traffic lights, order processing." },
  { id: "oop152", diff: "medium", topic: "Design", q: "What is the Visitor pattern?", opts: ["Visiting design websites", "Separating an algorithm from the object structure it operates on — add new operations without modifying the classes", "Object traversal pattern", "Database visitor pattern"], ans: 1, exp: "Visitor: add operations to object structures without modifying them. Element has accept(Visitor), Visitor has visit(ConcreteElement). Double dispatch: the right visit() is chosen based on both element type and visitor type. Used in compilers (AST traversal)." },
  { id: "oop153", diff: "medium", topic: "Basics", q: "What is the difference between deep copy and clone() in Java?", opts: ["No difference", "clone() by default is a shallow copy (Object.clone()). Deep copy requires manually copying all referenced objects or using serialization/copy constructors", "clone() is always deep", "Deep copy is impossible in Java"], ans: 1, exp: "Object.clone() copies field values (shallow). For a deep copy: (1) Implement custom clone() that clones nested objects, (2) Use copy constructor, (3) Serialise and deserialise." },
  { id: "oop154", diff: "medium", topic: "Basics", q: "What is the 'Fragile Base Class' problem in OOP?", opts: ["Base classes with few methods", "When a change to a base class breaks subclasses, even though the subclasses didn't change — caused by inheritance coupling", "Null pointer from base classes", "Final class issues"], ans: 1, exp: "Fragile base class: adding/modifying a method in a base class can unexpectedly break subclasses that override related methods. This is why 'prefer composition over inheritance' is good advice." },
  { id: "oop155", diff: "medium", topic: "Design", q: "What is the difference between the Facade and Adapter patterns?", opts: ["No difference", "Facade: simplifies a complex subsystem with a higher-level interface. Adapter: converts one interface to another expected interface. Facade hides complexity; Adapter bridges incompatibility", "Adapter simplifies; Facade converts", "Both hide implementations"], ans: 1, exp: "Facade: creates a simple interface over a complex system. e.g., HomeTheaterFacade.watchMovie() calls TV.on(), DVD.play(). Adapter: converts existing interface to what client expects — wraps an incompatible object." },
  { id: "oop156", diff: "hard", topic: "JVM Internals", q: "How does Java implement runtime polymorphism at the JVM level?", opts: ["Via static binding at compile time", "Via a vtable (virtual method table) — each object has a pointer to its class's vtable, and virtual method calls are dispatched through this table at runtime", "Via reflection only", "Via bytecode rewriting"], ans: 1, exp: "JVM uses a vtable (virtual dispatch table): each class has a table of method pointers. When you call a virtual method, the JVM looks up the actual object's vtable and calls the correct implementation — O(1) dispatch." },
  { id: "oop157", diff: "hard", topic: "Design", q: "What is the difference between the Abstract Factory and Factory Method patterns?", opts: ["No difference", "Factory Method creates one product type via subclass override; Abstract Factory creates families of related products via an interface with multiple factory methods", "Abstract Factory is simpler", "Factory Method creates multiple products"], ans: 1, exp: "Factory Method: one method, one product type, subclasses override it. Abstract Factory: an interface for creating FAMILIES of related products (Button, TextField, Scrollbar) — different factories for different platforms produce compatible families." },
  { id: "oop158", diff: "hard", topic: "Design", q: "What is the Flyweight pattern and when is it useful?", opts: ["A pattern for lightweight threads", "A pattern that shares fine-grained objects to reduce memory — intrinsic state is shared; extrinsic state is passed", "A pattern for singleton creation", "A pattern for lazy loading"], ans: 1, exp: "Flyweight: share objects to support many similar objects efficiently. Java String pool and Integer.valueOf() (-128 to 127 cache) are examples. Intrinsic state (shared) vs extrinsic state (context-specific, passed in)." },
  { id: "oop159", diff: "hard", topic: "Basics", q: "Explain the double-checked locking Singleton pattern. What problem does 'volatile' solve here?", opts: ["Volatile is not needed", "Without volatile, due to CPU instruction reordering, a partially constructed object could be seen by another thread before the field is fully initialised", "Volatile prevents GC", "Volatile makes the constructor thread-safe"], ans: 1, exp: "Double-checked: if(instance==null){synchronized{if(instance==null){instance=new S()}}}. Without volatile, CPU can reorder: allocate memory → assign reference → initialise. Another thread sees non-null but uninitialised object. volatile prevents reordering." },
  { id: "oop160", diff: "hard", topic: "Generics", q: "Why can't you create generic arrays in Java? e.g., new T[]", opts: ["Syntax limitation", "Type erasure: at runtime, T is erased to Object. An array of T[] would actually be Object[], but arrays are covariant and reifiable — this creates heap pollution and type unsafety", "Memory limitation", "JVM limitation"], ans: 1, exp: "Arrays are covariant (String[] IS-A Object[]) and reifiable (type info kept at runtime). Generics are invariant and erased. If T[] were allowed, you could insert the wrong type at runtime — heap pollution. Use List<T> instead." },
  { id: "oop161", diff: "hard", topic: "JVM Internals", q: "What is the difference between stack memory and heap memory in Java OOP context?", opts: ["No difference", "Stack: per-thread, stores local variables and method call frames (fast). Heap: shared, stores all objects created with 'new' (slower, GC-managed)", "Heap is per-thread", "Stack stores objects"], ans: 1, exp: "Stack: LIFO, each thread has its own, stores method call frames, local variables, and primitive values. Fast allocation/deallocation. Heap: shared among threads, stores all objects (new). GC manages it." },
  { id: "oop162", diff: "hard", topic: "Design", q: "What is the Interpreter pattern?", opts: ["Code interpretation at runtime", "Defining a representation for a grammar and an interpreter that uses that representation to interpret sentences — used for simple languages/rules engines", "A compiler design pattern", "A JVM pattern"], ans: 1, exp: "Interpreter: each grammar rule is a class. Abstract expression has interpret() method. Used for: scripting languages, regular expressions, SQL parsing, rule engines." },
  { id: "oop163", diff: "hard", topic: "Basics", q: "What is the difference between association, aggregation, and composition?", opts: ["They are the same", "Association: general 'uses' relationship. Aggregation: HAS-A with independent lifecycle. Composition: HAS-A with dependent lifecycle (child dies with parent)", "Composition is weakest", "Aggregation implies inheritance"], ans: 1, exp: "Association: Teacher teaches Student (no ownership). Aggregation: Team HAS Players (Players exist independently). Composition: Human HAS-A Heart (Heart dies with Human). Increasing strength: association < aggregation < composition." },
  { id: "oop164", diff: "hard", topic: "JVM Internals", q: "What is the difference between static dispatch and dynamic dispatch in Java?", opts: ["No difference", "Static dispatch: method resolved at compile time (overloading, static methods). Dynamic dispatch: method resolved at runtime using vtable (overriding, virtual methods)", "Dynamic dispatch is slower only", "Static dispatch is for interfaces"], ans: 1, exp: "Static dispatch: overloaded method is chosen by the compiler based on declared type and parameter signature. Dynamic dispatch: overridden method is chosen by JVM at runtime based on actual object type." },
  { id: "oop165", diff: "hard", topic: "Basics", q: "What is a mixin in OOP and how can Java simulate it?", opts: ["A compilation phase", "A way to add multiple behaviours to a class without inheritance — Java simulates via interfaces with default methods (Java 8+)", "A type of constructor", "A generic type"], ans: 1, exp: "Mixin: add a set of methods to a class without inheritance. Java 8 default methods enable this: interface Flyable { default void fly() {...} } — a class can mix in multiple behaviours by implementing multiple interfaces with default methods." },
  { id: "oop166", diff: "hard", topic: "Basics", q: "What is type coercion vs type casting in Java?", opts: ["They are the same", "Type coercion: automatic implicit conversion (int to double). Type casting: explicit conversion (double to int with possible data loss)", "Casting is implicit", "Coercion requires explicit syntax"], ans: 1, exp: "Widening coercion: int → long → float → double (automatic, no data loss). Narrowing casting: (int) 3.14 → 3 (explicit, may lose data). Object casting: (String) obj — explicit, can throw ClassCastException if wrong type." },
  { id: "oop167", diff: "hard", topic: "Basics", q: "What is the difference between deep copy and clone() in Java?", opts: ["No difference", "clone() by default is a shallow copy (Object.clone()). Deep copy requires manually copying all referenced objects or using serialization/copy constructors", "clone() is always deep", "Deep copy is impossible in Java"], ans: 1, exp: "Object.clone() copies field values (shallow). For a deep copy: (1) Implement custom clone() that clones nested objects, (2) Use copy constructor, (3) Serialise and deserialise." },
  { id: "oop168", diff: "hard", topic: "Design", q: "What is the difference between the Proxy and Decorator patterns?", opts: ["No difference", "Proxy controls access to an object (may add lazy init, security, logging). Decorator adds behaviour to an object dynamically. Both use the same interface but differ in intent and how they are composed", "Decorator controls access; Proxy adds behaviour", "They are the same structural pattern"], ans: 1, exp: "Proxy: focuses on controlling access to the real object — often the proxy creates the real object lazily or controls who can use it. Decorator: focuses on adding functionality — stacked at runtime. Both implement the same interface and delegate, but their PURPOSE differs." },
  { id: "oop169", diff: "hard", topic: "Basics", q: "What is the 'Fragile Base Class' problem in OOP?", opts: ["Base classes with few methods", "When a change to a base class breaks subclasses, even though the subclasses didn't change — caused by inheritance coupling", "Null pointer from base classes", "Final class issues"], ans: 1, exp: "Fragile base class: adding/modifying a method in a base class can unexpectedly break subclasses that override related methods. The subclass assumes certain behaviour that changes. This is why 'prefer composition over inheritance' and 'design for inheritance or prohibit it (final)'." },
  { id: "oop170", diff: "hard", topic: "Basics", q: "What is reflection in Java and what are its trade-offs?", opts: ["Mirroring code", "The ability to inspect and manipulate classes, methods, and fields at runtime — even private members. Trade-offs: loses compile-time safety, slower, breaks encapsulation", "Only for debugging", "No trade-offs"], ans: 1, exp: "Reflection (java.lang.reflect): inspect Class objects, list methods/fields, invoke methods by name, create instances dynamically. Powers: Spring, JUnit, Jackson. Trade-offs: ~20-50x slower than direct calls, no compile-time safety, breaks encapsulation, security manager restrictions." },
  { id: "oop171", diff: "scenario", topic: "Design Problem", q: "You're building a payment system that needs to support credit card, PayPal, and cryptocurrency payments, with new payment methods added frequently. Which OOP design would you use?", opts: ["One large PaymentProcessor class with if/else for each type", "Strategy pattern: PaymentStrategy interface with CreditCardPayment, PayPalPayment, CryptoPayment implementations — swap at runtime without modifying existing code", "Singleton payment class", "Abstract class with switch statement"], ans: 1, exp: "Strategy pattern: each payment method implements PaymentStrategy.pay(). PaymentProcessor holds a reference and delegates. Adding a new method = new class, no existing code change (Open/Closed Principle). Clean, testable, extensible." },
  { id: "oop172", diff: "scenario", topic: "Debug", q: "Your HashMap is losing entries — you add an object as a key, modify the object's state, and can no longer find it with get(). What went wrong?", opts: ["HashMap bug", "The object's hashCode() changed after modification, placing it in a different bucket — HashMap lookup fails", "The object was garbage collected", "get() has a bug"], ans: 1, exp: "HashMap uses hashCode() to find the bucket. If you modify a key object after insertion (changing fields used in hashCode()), its hash changes. The entry is in the old bucket, but lookup computes a new bucket — entry appears lost. Always use immutable keys in HashMap." },
  { id: "oop173", diff: "scenario", topic: "Debug", q: "A Singleton class works fine in single-threaded tests but creates multiple instances in production. What's likely wrong?", opts: ["The Singleton pattern is broken", "The getInstance() check is not synchronized — two threads can simultaneously see instance==null and each create an object", "Garbage collector destroys instances", "The constructor is public"], ans: 1, exp: "Race condition: thread A and B both check instance==null (true), both enter the if block, both create instances. Fix: (1) synchronized getInstance(), (2) Double-checked locking with volatile, (3) Initialization-on-demand holder (best: JVM guarantees class loading is thread-safe)." },
  { id: "oop174", diff: "scenario", topic: "Design Problem", q: "You need to log method calls in a large existing codebase of 50+ classes without modifying any existing class. What's the best approach?", opts: ["Manually add logging to every method", "Use dynamic proxies or AOP (Aspect-Oriented Programming) — intercept method calls via proxy/aspect without touching original code", "Extend all classes", "Create a Logger subclass for each"], ans: 1, exp: "AOP/Proxy: create a logging handler that intercepts all method calls via java.lang.reflect.Proxy or a framework like AspectJ/Spring AOP. The @Before advice adds logging without modifying existing classes — perfect application of the Open/Closed Principle." },
  { id: "oop175", diff: "scenario", topic: "Design Problem", q: "You're designing a document editor with multiple output formats (PDF, HTML, XML). New formats will be added. Objects in the document have complex structures. Which pattern fits best?", opts: ["Factory Method", "Visitor pattern: document elements accept a visitor; each visitor (PdfExportVisitor, HtmlExportVisitor) implements the export — add new formats without modifying elements", "Singleton", "Command pattern"], ans: 1, exp: "Visitor: document elements (Paragraph, Image, Table) implement accept(Visitor v). Adding PDF export = new PdfVisitor class only. No modification to existing element classes. Double-dispatch ensures the right visit() method is called per element type." },
  { id: "oop176", diff: "scenario", topic: "Debug", q: "You override equals() in your class but forget to override hashCode(). Your object is added to a HashSet — when you check contains() with an equal object, it returns false. Explain.", opts: ["HashSet has a bug", "equals() and hashCode() contract violation: equal objects must have equal hash codes. The HashSet puts the object in one bucket (using default hashCode), but looks for it in a different bucket — never finds it", "The object was removed", "equals() override failed"], ans: 1, exp: "HashSet first computes hashCode() to find the bucket, then uses equals() to confirm. With default hashCode() (memory address), two logically equal objects hash to different buckets. The contract breach: equals()=true but hashCode() different means the HashSet can't find the object. Always override both together." },
  { id: "oop177", diff: "scenario", topic: "Design Problem", q: "You need an object that represents 'no customer' (default behaviour) to avoid null checks scattered throughout the codebase. What pattern applies?", opts: ["Singleton pattern", "Null Object pattern: create a NullCustomer that implements Customer with do-nothing/default methods", "Factory pattern", "Abstract class solution"], ans: 1, exp: "Null Object pattern: instead of if(customer != null) { customer.getDiscount(); } everywhere, a NullCustomer.getDiscount() returns 0. Client code doesn't need null checks. Cleaner code, no NullPointerExceptions, same interface as real customers." },
  { id: "oop178", diff: "scenario", topic: "Debug", q: "Your class hierarchy is becoming unmanageable — every new feature requires changes in the base class that break subclasses. What refactoring would you apply?", opts: ["Add more subclasses", "Replace inheritance with composition (strategy/delegation) — extract behaviours into interfaces, inject them, swap at runtime without fragile base class coupling", "Make the base class final", "Add more abstract methods"], ans: 1, exp: "Fragile base class problem. Solution: favour composition. Extract FlyBehaviour, QuackBehaviour interfaces. Duck has a FlyBehaviour (not IS-A). New behaviour = new class. No change to existing classes. This is the Head First Design Patterns 'Duck example' — classic composition over inheritance." },
  { id: "oop179", diff: "scenario", topic: "Design Problem", q: "You're building a notification system that sends alerts via email, SMS, and push notifications, and combinations of these. How do you design it to avoid class explosion?", opts: ["Create EmailSMSNotifier, EmailPushNotifier, SMSPushNotifier, EmailSMSPushNotifier classes", "Decorator pattern: wrap notifications around each other — new PushDecorator(new SMSDecorator(new EmailNotifier())) — combine behaviours at runtime", "Inheritance with all combinations", "Singleton notifier"], ans: 1, exp: "Decorator pattern: without it, you'd need 7 classes for all combinations of 3 notification types (class explosion). With decorator: each type is a decorator that wraps another Notifier. Combine freely at runtime. Adding a 4th type = one new class, not 8 more." },
  { id: "oop180", diff: "scenario", topic: "Design Problem", q: "You need to support undo/redo in a text editor. Which pattern would you implement?", opts: ["Observer pattern", "Command pattern with a history stack: each operation is a Command object with execute() and undo(). Maintain an undo stack and redo stack", "Strategy pattern", "Factory pattern"], ans: 1, exp: "Command pattern: TextCommand(InsertCommand, DeleteCommand) with execute()/undo(). Maintain undoStack and redoStack. Ctrl+Z: undoStack.pop().undo(), push to redoStack. Ctrl+Y: redoStack.pop().execute(), push to undoStack." },
  { id: "oop181", diff: "scenario", topic: "Debug", q: "You call a method on a subclass through a superclass reference and get unexpected behaviour. The parent method is calling a method that's been overridden in the child. What Java mechanism causes this?", opts: ["Bug in Java", "Dynamic dispatch / virtual method invocation: even when called from within the superclass constructor or method, the overridden version in the subclass is invoked — can cause issues in constructors", "Reflection issue", "Compile-time binding"], ans: 1, exp: "Dynamic dispatch: calls to overridden methods always dispatch to the most-derived implementation, even from within superclass code. Dangerous in constructors: if superclass constructor calls an overrideable method, the subclass override runs BEFORE the subclass constructor completes, accessing uninitialised fields." },
  { id: "oop182", diff: "scenario", topic: "Design Problem", q: "Your application needs to connect to different databases (MySQL, PostgreSQL, MongoDB) configurable at startup. How do you design database connectivity using OOP?", opts: ["Hardcode each database", "Abstract Factory: DatabaseFactory creates Connection, Statement, ResultSet families for each DB. Factory chosen at startup based on config. Client code works against interfaces only", "Singleton connection", "if/else for each database"], ans: 1, exp: "Abstract Factory: MySQLFactory, PostgresFactory, MongoFactory each implement DatabaseFactory creating compatible Connection, QueryBuilder, ResultParser families. Swap factory at startup. Client code never sees DB-specific classes — pure interface programming." },
  { id: "oop183", diff: "scenario", topic: "Debug", q: "You use a List<Dog> where a List<Animal> is expected and get a compile error, even though Dog extends Animal. Why?", opts: ["Compiler bug", "Java generics are invariant — List<Dog> is NOT a subtype of List<Animal>. If it were, you could add a Cat to a List<Dog> via the List<Animal> reference — type safety would break", "Incorrect class hierarchy", "Classloader issue"], ans: 1, exp: "Invariance: even though Dog IS-A Animal, List<Dog> IS-NOT-A List<Animal>. Consider: if allowed, List<Animal> animals = dogList; animals.add(new Cat()); — dogList now contains a Cat! Use wildcard: List<? extends Animal> for read-only access to any animal list." },
  { id: "oop184", diff: "scenario", topic: "Design Problem", q: "You're designing a file system with files and directories, where directories can contain other directories and files, and you want to treat files and directories uniformly for operations like size() and print(). Which pattern?", opts: ["Inheritance only", "Composite pattern: FileSystemComponent interface with File (leaf) and Directory (composite containing a List<FileSystemComponent>). size() and print() work uniformly on both", "Observer pattern", "Decorator pattern"], ans: 1, exp: "Composite pattern: Directory.size() = sum of children's size(). File.size() = actual size. Client calls root.size() without caring about the tree structure. Perfectly models part-whole hierarchies like file systems, org charts, GUI component trees." },
  { id: "oop185", diff: "scenario", topic: "Design Problem", q: "A class has 12 constructor parameters, many optional. Objects are hard to create correctly. Which design pattern solves this?", opts: ["Factory Method", "Builder pattern: MyClass obj = new MyClass.Builder().name('A').age(25).email('x').build() — fluent, readable, validates at build() call, avoids telescoping constructors", "Singleton pattern", "Abstract Factory"], ans: 1, exp: "Builder pattern: telescoping constructors (overloading for each parameter combination) are unreadable and error-prone. Builder provides a fluent interface, makes optional vs required clear, validates at build(), and creates immutable objects." },
  { id: "oop186", diff: "scenario", topic: "Debug", q: "You implement Cloneable and call super.clone(), but changes to the cloned object still affect the original. What's the problem?", opts: ["clone() doesn't work", "Object.clone() performs a shallow copy — reference fields in the clone point to the SAME objects as the original. You must manually deep-clone each mutable reference field", "Cloneable is broken", "The objects are shared by design"], ans: 1, exp: "Shallow clone: primitive fields are copied (independent). Reference fields point to the SAME objects. Modifying a nested list in the clone modifies the original's list too. Deep copy: clone.list = new ArrayList<>(this.list) in your overridden clone() method." },
  { id: "oop187", diff: "scenario", topic: "Design Problem", q: "You need to add caching to an existing database access class without modifying it (it's from a third-party library). Which pattern?", opts: ["Extend the class", "Proxy pattern: create a CachingProxy that implements the same interface, wraps the real DatabaseAccessor, checks cache before delegating to the real object", "Decorator pattern", "Adapter pattern"], ans: 1, exp: "Proxy pattern (caching proxy): wraps the real object with the same interface, checks cache before calling the real method, and stores results. Client code unchanged." },
  { id: "oop188", diff: "scenario", topic: "Debug", q: "You have a class with 20 methods. Some implementing classes only use 3 of these methods but are forced to implement all 20 with empty bodies. What principle is being violated?", opts: ["Single Responsibility", "Interface Segregation Principle (ISP): one fat interface forces clients to depend on methods they don't use. Solution: split into smaller, focused interfaces", "Dependency Inversion", "Liskov Substitution"], ans: 1, exp: "ISP violation: a Printable interface with print(), scan(), fax(), copy() forces a SimplePrinter to implement scan(), fax(), copy() with empty/exception bodies. Split: Printable, Scannable, Faxable. SimplePrinter only implements Printable." },
  { id: "oop189", diff: "scenario", topic: "Design Problem", q: "You're building a GUI framework. You want button click events to trigger multiple independent actions (logging, analytics, UI update) without coupling the button to those actions. Which pattern?", opts: ["Direct method calls in button", "Observer pattern: Button (Subject) notifies all registered ActionListeners (Observers) on click. Add/remove listeners at runtime without modifying Button", "Singleton observer", "Factory pattern"], ans: 1, exp: "Observer: Java's ActionListener, EventListener, and the entire AWT/Swing event system use this. Button.addActionListener(listener) registers observers. On click, notifyAll() fires all listeners independently." },
  { id: "oop190", diff: "scenario", topic: "Debug", q: "You notice that subclassing a third-party class and overriding its methods causes unexpected behaviour after a library update. The base class added a new method that calls your overridden method. What principle applies?", opts: ["Just update your code", "Fragile base class problem + violation of Design for Inheritance or prohibit it. Solution: prefer composition (wrap the third-party class) rather than extending it", "File a bug report", "Use reflection instead"], ans: 1, exp: "When you extend a class, you're tightly coupled to its internals. A base class update can break subclasses unexpectedly. Joshua Bloch's advice: 'Design and document for inheritance, or else prohibit it (make class final).' Wrapping (composition) is safer." },
  { id: "oop191", diff: "scenario", topic: "Design Problem", q: "You need to parse multiple configuration formats (JSON, XML, YAML). The parsing logic is similar — read source, validate, map to domain objects. Only the reading step differs. Which pattern?", opts: ["One parser with if/else", "Template Method pattern: abstract ConfigParser with final parseConfig() calling abstract readSource() + concrete validate() + mapToDomain(). Subclasses (JsonParser, XmlParser) only override readSource()", "Strategy pattern", "Factory pattern"], ans: 1, exp: "Template Method: the algorithm skeleton (read→validate→map) is fixed in the base class. Only the varying step (readSource) is abstract. Each format subclass implements just readSource(). Avoids code duplication in the common steps." },
  { id: "oop192", diff: "scenario", topic: "Debug", q: "Your TreeSet<MyClass> is throwing a ClassCastException when adding a second element. What's likely missing from MyClass?", opts: ["A constructor", "MyClass doesn't implement Comparable<MyClass>. TreeSet requires elements to be comparable (uses compareTo() to maintain sorted order). Without it, adding the 2nd element fails when TreeSet tries to compare it", "A toString() method", "A hashCode() method"], ans: 1, exp: "TreeSet (and sorted collections) requires elements to implement Comparable or a Comparator to be provided. Without compareTo(), TreeSet can't determine element order and throws ClassCastException on the 2nd add." },
  { id: "oop193", diff: "scenario", topic: "Design Problem", q: "You need to implement a logging framework where different loggers (ConsoleLogger, FileLogger, EmailLogger) handle messages at different severity levels and can be chained. Which pattern fits?", opts: ["Observer pattern", "Chain of Responsibility: each logger has a next reference and handles messages at or above its level, passing lower-severity messages up the chain", "Strategy pattern", "Command pattern"], ans: 1, exp: "CoR: ConsoleLogger handles DEBUG (passes ERROR up). FileLogger handles WARN (passes ERROR up). EmailLogger handles ERROR. Chain: console→file→email. A DEBUG message is handled by console only. An ERROR message propagates the whole chain." },
  { id: "oop194", diff: "scenario", topic: "Design Problem", q: "You're designing a hotel booking system. Rooms have states (Available, Reserved, CheckedIn, CheckedOut). Behaviour differs significantly by state. Which pattern?", opts: ["Multiple if/else blocks", "State pattern: Room has a RoomState field. Each state class (AvailableState, ReservedState, CheckedInState) implements RoomState and defines transitions. Room delegates behaviour to current state", "Singleton pattern", "Command pattern"], ans: 1, exp: "State pattern: eliminates massive if/else. AvailableState.reserve() → transitions to ReservedState. ReservedState.checkIn() → CheckedInState. Adding a new state = new class. Room class stays clean." },
  { id: "oop195", diff: "scenario", topic: "Debug", q: "You're using a for-each loop over a collection and deleting elements inside the loop. You get ConcurrentModificationException. How do you fix it?", opts: ["Use a regular for loop", "Use Iterator explicitly and call iterator.remove() — the only safe way to remove elements during iteration without ConcurrentModificationException", "Use ArrayList instead", "Use removeAll()"], ans: 1, exp: "for-each uses the fail-fast iterator. Any structural modification (add/remove) via the Collection directly increments modCount, which the iterator checks — throws CME. Fix: Iterator<T> it = list.iterator(); while(it.hasNext()){ if(condition) it.remove(); }. Or use removeIf() (Java 8+)." },
  { id: "oop196", diff: "scenario", topic: "Design Problem", q: "You need a global configuration object accessible throughout the application, initialised once from a config file, thread-safe. Which pattern and implementation?", opts: ["Static class with public fields", "Singleton with Initialization-on-demand holder idiom: private static class Holder { static final Config INSTANCE = new Config(); } — thread-safe without synchronisation overhead, lazy initialisation", "A global variable", "A static utility class"], ans: 1, exp: "Initialization-on-demand holder: getInstance() returns Holder.INSTANCE. The Holder class is only loaded when getInstance() is first called (lazy). JVM class loading is thread-safe by specification — no synchronisation needed. Best practice for lazy, thread-safe Singleton." },
  { id: "oop197", diff: "scenario", topic: "Debug", q: "You have a class Animal with method makeSound(). Dog overrides it. You create Dog d = new Dog(); Animal a = d; then call a.makeSound(). Which version runs?", opts: ["Animal's makeSound()", "Dog's makeSound() — runtime polymorphism: the actual object type (Dog) determines which method runs, regardless of reference type (Animal)", "Both versions run", "Compile error"], ans: 1, exp: "Runtime polymorphism (dynamic dispatch): the JVM looks at the actual object type (Dog), not the reference type (Animal). Dog's makeSound() runs. This is the core of polymorphism — 'program to the interface, not the implementation.'" },
  { id: "oop198", diff: "scenario", topic: "Design Problem", q: "You're building a data access layer. Business logic classes directly instantiate DAO classes. This makes unit testing impossible (can't mock DBs). How do you fix it?", opts: ["Use static methods in DAO", "Apply Dependency Injection with DAO interfaces: business classes depend on IUserDao (interface), DAOs injected via constructor. Tests inject MockUserDao instead of real DB DAOs — fully testable", "Use Singleton DAO", "Add test flags in production code"], ans: 1, exp: "DI + Interface Segregation: business class receives IUserDao in constructor. Production: inject JdbcUserDao. Test: inject MockUserDao. No real DB needed in tests. Spring/Dagger manage injection in production. This is the Dependency Inversion Principle — depend on abstractions, not concretions." },
  { id: "oop199", diff: "scenario", topic: "Debug", q: "A Java program runs correctly single-threaded but produces wrong results with multiple threads accessing and modifying a shared object. The object uses no synchronisation. What OOP design helps?", opts: ["Use synchronized everywhere", "Make the shared object immutable — if its state cannot change after creation, threads can safely share it without synchronisation, eliminating race conditions. Or use thread-safe wrappers", "Use singleton", "Use volatile on all fields"], ans: 1, exp: "Immutability is the safest concurrency strategy. Immutable objects (final fields, no setters, defensive copies) can be shared freely between threads with no synchronisation overhead. For mutable state, use ConcurrentHashMap, AtomicInteger, or synchronized blocks." },
  { id: "oop200", diff: "scenario", topic: "Design Problem", q: "You need to add spell-check, grammar-check, and formatting as optional features to a text processor, where users can choose any combination. Class-based inheritance would cause an explosion of subclasses. Which pattern?", opts: ["Create all combination subclasses", "Decorator pattern: SpellCheckDecorator, GrammarDecorator, FormattingDecorator all extend TextProcessor. Combine: new SpellCheckDecorator(new GrammarDecorator(new FormattingDecorator(basicProcessor)))", "Abstract factory", "Composite pattern"], ans: 1, exp: "Decorator avoids class explosion: 3 features = 7 combination classes with inheritance vs 3 decorator classes. Attach/detach at runtime. Each decorator wraps and enhances the same interface. Java I/O is the canonical example." },
  { id: "oop201", diff: "scenario", topic: "Design Problem", q: "Your e-commerce app's Order class handles: persistence (SQL), email sending, PDF generation, and discount calculation — all in one class. What principle is violated and how do you refactor?", opts: ["Nothing is wrong", "Single Responsibility Principle: Order has too many reasons to change. Refactor: OrderRepository (persistence), EmailService (notifications), InvoiceGenerator (PDF), DiscountCalculator (pricing). Order only manages order data.", "Use inheritance", "Use static methods"], ans: 1, exp: "SRP: a class should have only one reason to change. If SQL schema changes, Order changes. If email template changes, Order changes. If discount rules change, Order changes. Extract: OrderRepository, NotificationService, InvoiceService, PricingEngine." },
  { id: "oop202", diff: "scenario", topic: "Debug", q: "You're using Java serialization. After changing a class (adding a field), deserialization of old data fails with InvalidClassException. How do you fix this?", opts: ["Don't add fields ever", "Declare a private static final long serialVersionUID in your class. This explicit UID persists across versions. Without it, Java auto-generates UID based on class structure — any change generates a new UID, making old data incompatible", "Use transient on all fields", "Recreate the file"], ans: 1, exp: "serialVersionUID: explicitly declare private static final long serialVersionUID = 1L; Java uses this to verify compatibility between serialized and current class versions. Without it: adding a field changes auto-generated UID → InvalidClassException." },
  { id: "oop203", diff: "scenario", topic: "Design Problem", q: "You're building a plugin architecture where new plugins can be added without recompiling the core application. Each plugin implements a specific interface. How do OOP principles enable this?", opts: ["Hardcode all plugins", "Open/Closed Principle + interface programming: core depends only on PluginInterface. Plugins are separate JARs loaded at runtime via ServiceLoader or reflection, implementing the interface. Core never changes when new plugins are added", "Singleton pattern", "Abstract classes for each plugin type"], ans: 1, exp: "OCP + polymorphism + interface-based programming: core code is closed for modification, open for extension (new plugin = new JAR). java.util.ServiceLoader discovers implementations of a service interface from classpath." },
  { id: "oop204", diff: "scenario", topic: "Debug", q: "You define a method add(int a, int b) and add(double a, double b) (overloaded). When you call add(1, 2.0), which version is called?", opts: ["Compile error", "add(double, double): Java promotes int to double for the 2nd argument. Since one argument is already double, Java widens the int to double and calls the double version", "add(int, int)", "Ambiguous — runtime error"], ans: 1, exp: "Method resolution for overloading: Java prefers widening over boxing over varargs. int can be widened to double, so add(1, 2.0) → add(double 1.0, double 2.0). Order: widening > boxing > varargs." },
  { id: "oop205", diff: "scenario", topic: "Design Problem", q: "You need to access a remote service (on another server) using the same interface as a local service, with network error handling and retries transparent to the caller. Which pattern?", opts: ["Direct HTTP calls everywhere", "Remote Proxy: RemoteServiceProxy implements the same interface as the local service, handles network communication, serialisation, retries, and error handling transparently. Client code calls the proxy exactly like a local object", "Adapter pattern", "Facade pattern"], ans: 1, exp: "Remote Proxy (RPC/RMI concept): client calls interface methods; proxy marshals parameters, sends over network, receives response, unmarshals result. Client is unaware of network details. Spring Feign Client is a modern REST proxy." },
  { id: "oop206", diff: "scenario", topic: "Debug", q: "You make an interface I with a default method m(). Class A implements I. Class B extends A. You call new B().m(). Which m() is called?", opts: ["Interface I's default m()", "A's m() if A overrides it, otherwise I's default m(). B inherits from A first (class over interface), then from I. Class implementations always take priority over interface defaults", "B gets compile error", "Ambiguous — runtime exception"], ans: 1, exp: "Resolution order: (1) class override wins over default method, (2) more specific interface default wins over less specific. So: if A overrides m() → A's version is called (B inherits it). If A doesn't override → I's default runs." },
  { id: "oop207", diff: "scenario", topic: "Design Problem", q: "You have 10 report types (SalesReport, InventoryReport, etc.), each needing to be exported to 3 formats (PDF, Excel, CSV). Which pattern avoids creating 30 classes?", opts: ["Create all 30 classes", "Visitor pattern OR Bridge pattern: Bridge separates Report (abstraction) from ExportFormat (implementation). SalesReport uses a PDF ExportFormat. 10 + 3 = 13 classes instead of 30. Adding a new format = 1 new class", "Strategy pattern only", "Template Method only"], ans: 1, exp: "Bridge pattern: decouple abstraction (Report types) from implementation (Export formats). Report has a reference to ExportFormat interface. 10 Report classes + 3 ExportFormat classes = 13. Combinations are composed at runtime." },
  { id: "oop208", diff: "scenario", topic: "Debug", q: "You create class B extends A. A has a constructor A(int x). You don't write any constructor in B. Does B compile?", opts: ["Yes, B uses A's constructor directly", "No — if A has no default no-arg constructor, B must explicitly call super(int x) in a constructor. Java doesn't automatically forward parameterised constructors to subclasses", "Yes, Java auto-generates super() calls with parameters", "Only if A is abstract"], ans: 1, exp: "If A has A(int x) but NO A() (no-arg), then Java's implicit super() in B's default constructor fails — A doesn't have a no-arg constructor. B must define a constructor and explicitly call super(someInt)." },
  { id: "oop209", diff: "scenario", topic: "Design Problem", q: "You need to guarantee that specific initialisation steps always happen in a particular order when creating objects of a class hierarchy. Which OOP feature helps?", opts: ["Static methods", "Constructor chaining with super(): Java enforces that the superclass constructor runs before the subclass constructor. Combined with Template Method in constructors (avoiding overrideable method calls), you can guarantee initialisation order", "Interfaces", "Abstract methods"], ans: 1, exp: "Constructor chaining (super()) guarantees parent initialisation before child. However, avoid calling overrideable methods in constructors (dynamic dispatch can call child's method before child fields initialise)." },
  { id: "oop210", diff: "scenario", topic: "Debug", q: "You call getClass() on an object and get 'class Dog', but the variable is declared as Animal. How do you explain this to a junior developer?", opts: ["It's a bug", "getClass() always returns the runtime class of the actual object (Dog), not the declared type of the variable (Animal). This is the fundamental nature of OOP — the object knows what it actually is, regardless of the reference type pointing to it", "Animal reference hides Dog's class", "Reflection error"], ans: 1, exp: "getClass() is a final method from Object that returns the actual runtime class. No matter what reference type you use (Animal, Object), the actual object was created as 'new Dog()' — getClass() returns Dog.class." },
  { id: "oop211", diff: "scenario", topic: "Design Problem", q: "Thread1 locks resource A then waits for B. Thread2 locks B then waits for A. Application freezes. What OOP design prevents this?", opts: ["Use more threads", "Deadlock prevention via consistent lock ordering — always acquire locks in the same order everywhere. Or use immutable objects (no locking needed), or compose behavior via message passing (actor model)", "Use synchronized on all methods", "Restart the JVM"], ans: 1, exp: "Deadlock prevention: 1) Lock ordering: always acquire locks in the same global order. 2) tryLock(timeout): give up if can't acquire. 3) Immutable objects: no shared mutable state = no locks needed. 4) ConcurrentHashMap, AtomicInteger instead of manual synchronisation." },
  { id: "oop212", diff: "scenario", topic: "Design Problem", q: "You need a type-safe heterogeneous container that can store objects of different types and retrieve them with full compile-time type safety. What OOP technique enables this?", opts: ["Use Object references with casting", "Type-safe heterogeneous container using Class<T> tokens as keys: Map<Class<?>, Object> map; <T> void put(Class<T> type, T value); <T> T get(Class<T> type). Josh Bloch's pattern from Effective Java", "Use instanceof for each type", "Use a wrapper class for each type"], ans: 1, exp: "Type-safe heterogeneous container (Effective Java Item 33): instead of Map<String, Object>, use Map<Class<?>, Object> where the key is the type token. put(String.class, 'hello'). get(String.class) returns a String without casting. The Class<T> token carries the type information safely." },
  { id: "oop213", diff: "scenario", topic: "Design Problem", q: "Your application generates complex objects (Orders, Reports, Invoices) and the creation logic is getting mixed with business logic. How do you cleanly separate object creation from usage?", opts: ["Put all creation in constructors", "Factory Method, Abstract Factory, or Builder pattern: creation logic is encapsulated in factory classes or builder objects. Business logic only uses the created objects, never 'new'. Follow the principle 'Tell, Don't Ask' and 'Dependency Inversion'", "Use Singleton for each type", "Use static factory methods only"], ans: 1, exp: "Separating creation from usage: 1) Factory classes encapsulate creation logic. 2) Dependency Injection: inject created objects. 3) Builder: for complex object construction. Business logic depends on interfaces (DIP), not 'new ConcreteClass()'. This makes code testable (inject mocks) and flexible (swap implementations)." },
  { id: "oop214", diff: "scenario", topic: "Debug", q: "You have a class with only static methods and a private constructor (utility class). A developer is trying to extend it. What problem does extending a utility class cause?", opts: ["No problem — it works fine", "Extending a utility class violates its design intent — instances of the subclass would expose an instance with no instance state. The public no-arg constructor in the subclass would call the private super() constructor — compile error. Make utility classes final to prevent extension", "Simply override the constructor", "Use abstract instead of final"], ans: 1, exp: "Utility classes (Math, Arrays, Collections) should be final with a private constructor: private UtilityClass() { throw new AssertionError(); }. This prevents: (1) instantiation, (2) extension (subclass would need to call super() which is private). Making it final explicitly communicates the design intent." },
  { id: "oop215", diff: "scenario", topic: "Design Problem", q: "You have a List<String> returned by a library method. You want to ensure the caller cannot modify the returned list. How do you enforce this with OOP?", opts: ["Return List<String> directly", "Return Collections.unmodifiableList(list) — a view that throws UnsupportedOperationException on any modification attempt. Or return List.copyOf(list) for an immutable copy (Java 10+). Or return an ImmutableList (Guava)", "Make the List final", "Return an array instead"], ans: 1, exp: "Defensive programming: Collections.unmodifiableList() wraps the list — any mutating operation throws UnsupportedOperationException at runtime. List.copyOf() creates a truly independent immutable copy. Best practice: return interfaces (List) not implementations, and wrap when mutation should be prevented." },
  { id: "oop216", diff: "scenario", topic: "Debug", q: "You have an interface with 5 methods. You implement it in 3 places, but each implementation only really uses 2-3 methods. The others have empty or stub bodies. What SOLID violation is this and how do you fix it?", opts: ["SRP violation", "ISP (Interface Segregation Principle) violation: the interface is too fat — clients are forced to depend on methods they don't use. Fix: split into 2-3 smaller, focused interfaces. Implementing classes implement only the interfaces they actually need", "DIP violation", "LSP violation"], ans: 1, exp: "ISP: one fat interface with 5 methods forces all implementors to know about all 5. Split: if methods A,B are about reading and C,D,E about writing, create ReadableInterface and WritableInterface. Implementations implement only what they use. No more stub bodies." },
  { id: "oop217", diff: "scenario", topic: "Design Problem", q: "A legacy class LegacyCalculator.compute(double[], String) must be used where your system expects Calculator.calculate(List<Double>). You cannot change either class. What pattern do you use?", opts: ["Just use instanceof and cast", "Adapter pattern: create LegacyCalculatorAdapter implementing Calculator. Internally: convert List<Double> to double[], call LegacyCalculator.compute(), map 'operation' String. Client code only sees Calculator interface", "Extend LegacyCalculator", "Use reflection to call the method"], ans: 1, exp: "Adapter Pattern: LegacyCalculatorAdapter implements Calculator { private LegacyCalculator legacy = new LegacyCalculator(); public double calculate(List<Double> values){ double[] arr = values.stream().mapToDouble(Double::doubleValue).toArray(); return legacy.compute(arr, 'sum'); } }. Client code unchanged. Legacy code unchanged." },
  { id: "oop218", diff: "scenario", topic: "Design Problem", q: "You need to build a report generation system where the report generation process is: fetch data → format data → render report. Each step can vary independently. Which OOP pattern best models this pipeline?", opts: ["One monolithic generateReport() method", "Strategy Pattern for each step: DataFetcher, DataFormatter, ReportRenderer interfaces with interchangeable implementations. ReportGenerator holds references to each strategy. Combine different strategies at runtime for different report types", "Template Method only", "Builder pattern"], ans: 1, exp: "Strategy pipeline: ReportGenerator(DataFetcher fetcher, DataFormatter formatter, ReportRenderer renderer). DatabaseFetcher, CsvFormatter, PdfRenderer as concrete strategies. A monthly PDF report: new ReportGenerator(new DatabaseFetcher(), new CsvFormatter(), new PdfRenderer()). Each step is independently replaceable (OCP)." },
  { id: "oop219", diff: "scenario", topic: "Debug", q: "A method returns an Animal reference but the caller needs Dog-specific methods. The caller uses (Dog) animal without instanceof. This works in testing but fails in production. Why and how do you fix this?", opts: ["It's a JVM bug", "ClassCastException: in production, the method returns a Cat or another Animal subtype, not a Dog. The unchecked cast fails. Fix: (1) Always check instanceof before casting, (2) Better: add the needed behavior to the Animal interface (polymorphism), (3) Use visitor pattern if behavior addition is impossible", "Use a try-catch for ClassCastException", "Use reflection to check the type"], ans: 1, exp: "ClassCastException is a runtime error from unsafe downcasting. Root cause: the caller is making assumptions about the concrete type. Fix polymorphically: if Dog has bark(), add speak() to Animal and override it in Dog. If you must cast: if (animal instanceof Dog dog) { dog.bark(); }. Avoid casts — they break polymorphism." },
  { id: "oop220", diff: "scenario", topic: "Design Problem", q: "You're designing a validation framework. An Order must pass multiple validation rules (total > 0, customer exists, items in stock). New rules will be added over time. How do you design this?", opts: ["Long if-else chain in a validate() method", "Chain of Responsibility or Specification Pattern: each rule is a Validator class implementing Validator.validate(Order order). Rules chain together or compose with and()/or(). New rule = new Validator class. Open/Closed Principle: no modification to existing validators", "Add validation in the Order constructor", "Use reflection to discover validation rules"], ans: 1, exp: "Chain of Responsibility: MinimumTotalValidator → CustomerExistsValidator → ItemsInStockValidator. Each validates and either returns an error or passes to next. Alternatively: Specification Pattern — compose rules: minTotal.and(customerExists).and(inStock). Adding a new rule = one new class, zero existing code changes (OCP)." },
];

