function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function QuizPanel({ subjectKey }) {
  const S = SUBJECTS[subjectKey];
  const ALL = S.questions;
  const diffColors = S.diffColors;
  const diffKeys = Object.keys(diffColors);

  const STORAGE_KEY = `quiz_state_${subjectKey}`;
  const loadState = (key, defaultVal) => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed[key] !== undefined) return parsed[key];
      }
    } catch (e) { }
    return defaultVal;
  };

  const [diffFilter, setDiffFilter] = useState(() => loadState("diffFilter", "all"));
  const [topicFilter, setTopicFilter] = useState(() => loadState("topicFilter", "all"));
  const [answered, setAnswered] = useState(() => loadState("answered", {}));
  const [page, setPage] = useState(() => loadState("page", 0));
  const [ids, setIds] = useState(() => {
    const savedIds = loadState("ids", null);
    return (savedIds && savedIds.length === ALL.length) ? savedIds : ALL.map(q => q.id);
  });
  const [score, setScore] = useState(() => loadState("score", { correct: 0, total: 0 }));

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ diffFilter, topicFilter, answered, page, ids, score }));
  }, [diffFilter, topicFilter, answered, page, ids, score, STORAGE_KEY]);

  const TOPICS = useMemo(() => [...new Set(ALL.map(q => q.topic))].sort(), [ALL]);

  const filtered = useMemo(() => {
    return ids
      .map(id => ALL.find(q => q.id === id))
      .filter(q => q &&
        (diffFilter === "all" || q.diff === diffFilter) &&
        (topicFilter === "all" || q.topic === topicFilter)
      );
  }, [ids, diffFilter, topicFilter]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PER_PAGE));
  const safePage = Math.min(page, totalPages - 1);
  const pageItems = filtered.slice(safePage * PER_PAGE, safePage * PER_PAGE + PER_PAGE);

  function handleAnswer(qid, chosenIdx) {
    if (answered[qid] !== undefined) return;
    const q = ALL.find(x => x.id === qid);
    const isCorrect = chosenIdx === q.ans;
    setAnswered(prev => ({ ...prev, [qid]: { chosen: chosenIdx, correct: isCorrect } }));
    setScore(s => ({ correct: s.correct + (isCorrect ? 1 : 0), total: s.total + 1 }));
  }

  function applyDiff(v) { setDiffFilter(v); setPage(0); }
  function applyTopic(v) { setTopicFilter(v); setPage(0); }
  function doShuffle() { setIds(shuffle(ALL.map(q => q.id))); setPage(0); }
  function doReset() { setAnswered({}); setScore({ correct: 0, total: 0 }); setPage(0); setIds(ALL.map(q => q.id)); setDiffFilter("all"); setTopicFilter("all"); }
  function changePage(d) { setPage(p => Math.max(0, Math.min(totalPages - 1, p + d))); window.scrollTo({ top: 0, behavior: "smooth" }); }

  const acc = score.total > 0 ? Math.round((score.correct / score.total) * 100) : null;
  const progress = Math.round((Object.keys(answered).length / ALL.length) * 100);
  const accC = acc === null ? "#888" : acc >= 75 ? "#4ade80" : acc >= 50 ? "#fbbf24" : "#f87171";

  const diffCounts = useMemo(() => {
    const c = {};
    diffKeys.forEach(k => { c[k] = ALL.filter(q => q.diff === k).length; });
    return c;
  }, []);

  return (
    <div style={{ fontFamily: "system-ui, -apple-system, BlinkMacSystemFont, 'Inter', 'Segoe UI', Roboto, sans-serif" }}>

      {/* Score + Progress */}
      <div style={{
        display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", marginBottom: 14,
        background: "rgba(255,255,255,0.04)", backdropFilter: "blur(12px)", WebkitBackdropFilter: "blur(12px)", border: "1px solid rgba(255,255,255,0.08)",
        boxShadow: "0 4px 20px 0 rgba(0, 0, 0, 0.2)", borderRadius: 13, padding: "13px 20px"
      }}>
        <div>
          <div style={{ fontSize: 11, color: "#64748b", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: 3 }}>Score</div>
          <div style={{ fontSize: 22, fontWeight: 700, color: "#f1f5f9" }}>
            <span style={{ color: accC }}>{score.correct}</span>
            <span style={{ color: "#334155", fontSize: 18 }}> / {score.total}</span>
          </div>
        </div>
        {acc !== null && (
          <div style={{
            padding: "5px 13px", borderRadius: 20, fontSize: 13, fontWeight: 700,
            background: `${accC}18`, color: accC, border: `1px solid ${accC}40`
          }}>
            {acc}%
          </div>
        )}
        <div style={{ flex: 1, minWidth: 160 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
            <span style={{ fontSize: 11, color: "#64748b" }}>PROGRESS</span>
            <span style={{ fontSize: 11, color: "#64748b" }}>{Object.keys(answered).length}/{ALL.length}</span>
          </div>
          <div style={{ height: 5, background: "rgba(255,255,255,0.07)", borderRadius: 3 }}>
            <div style={{
              height: "100%", width: `${progress}%`,
              background: `linear-gradient(90deg,${S.accent},#4ade80)`,
              borderRadius: 3, transition: "width 0.4s"
            }} />
          </div>
        </div>
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 7, marginBottom: 12, flexWrap: "wrap" }}>
        {/* diff pills */}
        {[["all", "All", S.accent, S.accentBg], ...diffKeys.map(k => [k, diffColors[k].label, diffColors[k].color, diffColors[k].bg])].map(([k, lbl, c, bg]) => (
          <button key={k} onClick={() => applyDiff(k)} style={{
            fontSize: 12, padding: "6px 14px", borderRadius: 8, cursor: "pointer",
            fontWeight: diffFilter === k ? 700 : 400,
            background: diffFilter === k ? bg : "rgba(255,255,255,0.03)",
            color: diffFilter === k ? c : "#64748b",
            border: diffFilter === k ? `1px solid ${c}60` : "1px solid rgba(255,255,255,0.07)",
            fontFamily: "inherit", transition: "all 0.15s"
          }}>{lbl}{k !== "all" ? ` (${diffCounts[k] || 0})` : ""}</button>
        ))}

        <select value={topicFilter} onChange={e => applyTopic(e.target.value)} style={{
          fontSize: 12, padding: "6px 10px", background: "rgba(255,255,255,0.06)", color: "#cbd5e1",
          border: "1px solid rgba(255,255,255,0.1)", borderRadius: 8, cursor: "pointer",
          outline: "none", fontFamily: "inherit"
        }}>
          <option value="all" style={{ background: "#111" }}>All Topics</option>
          {TOPICS.map(t => <option key={t} value={t} style={{ background: "#111" }}>{t}</option>)}
        </select>

        <div style={{ marginLeft: "auto", display: "flex", gap: 7 }}>
          {[["🔀 Shuffle", doShuffle], ["↺ Reset", doReset]].map(([l, fn]) => (
            <button key={l} onClick={fn} style={{
              fontSize: 12, padding: "6px 12px",
              background: "rgba(255,255,255,0.05)", color: "#cbd5e1",
              border: "1px solid rgba(255,255,255,0.09)", borderRadius: 8,
              cursor: "pointer", fontFamily: "inherit"
            }}>{l}</button>
          ))}
        </div>
        <span style={{ fontSize: 11, color: "#475569", alignSelf: "center" }}>{filtered.length} questions</span>
      </div>

      {/* Questions */}
      {pageItems.map(q => {
        const result = answered[q.id];
        const done = result !== undefined;
        const chosen = done ? result.chosen : null;
        const wasRight = done ? result.correct : null;
        const dm = diffColors[q.diff] || diffColors.easy;

        return (
          <div key={q.id} style={{
            background: "rgba(255,255,255,0.035)",
            backdropFilter: "blur(12px)",
            WebkitBackdropFilter: "blur(12px)",
            border: done
              ? wasRight ? "1px solid rgba(74,222,128,0.4)" : "1px solid rgba(248,113,113,0.4)"
              : "1px solid rgba(255,255,255,0.08)",
            boxShadow: "0 8px 32px 0 rgba(0, 0, 0, 0.2)",
            borderRadius: 13, padding: "20px 22px", marginBottom: 14, transition: "all 0.3s ease"
          }}>
            {/* meta */}
            <div style={{ display: "flex", gap: 7, marginBottom: 11, alignItems: "center", flexWrap: "wrap" }}>
              <span style={{
                fontSize: 11, fontWeight: 700, color: S.accent,
                background: `${S.accent}18`, padding: "2px 9px", borderRadius: 5
              }}>
                {q.id.toString().replace(/^(cn|oop|dsa|sql|java)/, "")}
              </span>
              <span style={{
                fontSize: 11, padding: "2px 9px", borderRadius: 5, fontWeight: 700,
                color: dm.color, background: dm.bg
              }}>{dm.label}</span>
              <span style={{
                fontSize: 11, padding: "2px 9px", borderRadius: 5,
                color: "#7dd3fc", background: "rgba(125,211,252,0.08)", fontStyle: "italic"
              }}>{q.topic}</span>
              {done && (
                <span style={{
                  marginLeft: "auto", fontSize: 13, fontWeight: 700,
                  color: wasRight ? "#4ade80" : "#f87171"
                }}>
                  {wasRight ? "✓ Correct" : `✗ Wrong — ${LABELS[q.ans]} is correct`}
                </span>
              )}
            </div>

            <div style={{ fontSize: 15, lineHeight: 1.7, color: "#e2e8f0", marginBottom: 14, whiteSpace: "pre-line" }}>
              {q.q}
            </div>

            {/* options */}
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {q.opts.map((opt, i) => {
                const isChosen = done && chosen === i;
                const isCorrectOpt = i === q.ans;
                const showGreen = done && isCorrectOpt;
                const showRed = done && isChosen && !isCorrectOpt;
                const showDim = done && !isCorrectOpt && !isChosen;

                let bg = "rgba(255,255,255,0.03)", border = "1px solid rgba(255,255,255,0.08)",
                  color = "#cbd5e1", dotBg = "rgba(255,255,255,0.08)", dotC = "#64748b", icon = null;

                if (showGreen) {
                  bg = "rgba(74,222,128,0.13)"; border = "1px solid #4ade8070";
                  color = "#bbf7d0"; dotBg = "#4ade80"; dotC = "#fff"; icon = "✓";
                } else if (showRed) {
                  bg = "rgba(248,113,113,0.13)"; border = "1px solid #f8717170";
                  color = "#fecaca"; dotBg = "#f87171"; dotC = "#fff"; icon = "✗";
                } else if (showDim) {
                  bg = "rgba(255,255,255,0.01)"; border = "1px solid rgba(255,255,255,0.04)";
                  color = "rgba(203,213,225,0.3)"; dotBg = "rgba(255,255,255,0.04)"; dotC = "rgba(100,116,139,0.4)";
                }

                return (
                  <button key={i} onClick={() => handleAnswer(q.id, i)} disabled={done}
                    style={{
                      width: "100%", textAlign: "left", padding: "10px 14px",
                      background: bg, border, borderRadius: 9, color,
                      cursor: done ? "default" : "pointer", fontSize: 14, lineHeight: 1.55,
                      display: "flex", gap: 11, alignItems: "flex-start",
                      fontFamily: "inherit", transition: "all 0.15s"
                    }}
                    onMouseEnter={e => { if (!done) { e.currentTarget.style.background = "rgba(255,255,255,0.07)"; e.currentTarget.style.border = "1px solid rgba(255,255,255,0.18)"; } }}
                    onMouseLeave={e => { if (!done) { e.currentTarget.style.background = bg; e.currentTarget.style.border = border; } }}>
                    <span className={isChosen ? "pop-anim" : ""} style={{
                      minWidth: 25, height: 25, borderRadius: "50%",
                      background: dotBg, display: "flex", alignItems: "center", justifyContent: "center",
                      fontSize: 11, fontWeight: 800, flexShrink: 0, color: dotC, marginTop: 1, transition: "transform 0.2s ease",
                      boxShadow: isChosen ? "0 0 10px rgba(255,255,255,0.2)" : "none"
                    }}>
                      {icon || LABELS[i]}
                    </span>
                    <span style={{ flex: 1 }}>{opt}</span>
                  </button>
                );
              })}
            </div>

            {/* explanation */}
            {done && (
              <div style={{
                marginTop: 13, padding: "12px 15px",
                background: wasRight ? "rgba(74,222,128,0.07)" : "rgba(99,102,241,0.07)",
                border: wasRight ? "1px solid rgba(74,222,128,0.25)" : "1px solid rgba(99,102,241,0.25)",
                borderRadius: 9
              }}>
                <div style={{
                  fontSize: 11, fontWeight: 800, letterSpacing: "0.5px", textTransform: "uppercase",
                  color: wasRight ? "#4ade80" : "#818cf8", marginBottom: 5
                }}>
                  {wasRight ? "✓ Correct!" : `✗ Correct Answer: ${LABELS[q.ans]}`}
                </div>
                <div style={{ fontSize: 13.5, lineHeight: 1.75, color: "#94a3b8" }}>{q.exp}</div>
              </div>
            )}
          </div>
        );
      })}

      {/* Pagination */}
      <div style={{ display: "flex", justifyContent: "center", alignItems: "center", gap: 10, marginTop: 8, flexWrap: "wrap" }}>
        <button onClick={() => changePage(-1)} disabled={safePage === 0}
          style={{
            padding: "8px 18px", fontSize: 13,
            background: safePage === 0 ? "rgba(255,255,255,0.02)" : "rgba(255,255,255,0.07)",
            color: safePage === 0 ? "#334155" : "#cbd5e1",
            border: "1px solid rgba(255,255,255,0.08)", borderRadius: 9,
            cursor: safePage === 0 ? "default" : "pointer", fontFamily: "inherit"
          }}>← Prev</button>

        <div style={{
          background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.08)",
          borderRadius: 9, padding: "8px 16px", fontSize: 12, color: "#64748b", textAlign: "center"
        }}>
          <strong style={{ color: "#e2e8f0" }}>{safePage + 1}</strong> / {totalPages}
          <span style={{ color: "#1e293b", margin: "0 7px" }}>·</span>
          Q{safePage * PER_PAGE + 1}–{Math.min((safePage + 1) * PER_PAGE, filtered.length)} of{" "}
          <strong style={{ color: "#e2e8f0" }}>{filtered.length}</strong>
        </div>

        <button onClick={() => changePage(1)} disabled={safePage >= totalPages - 1}
          style={{
            padding: "8px 18px", fontSize: 13,
            background: safePage >= totalPages - 1 ? "rgba(255,255,255,0.02)" : "rgba(255,255,255,0.07)",
            color: safePage >= totalPages - 1 ? "#334155" : "#cbd5e1",
            border: "1px solid rgba(255,255,255,0.08)", borderRadius: 9,
            cursor: safePage >= totalPages - 1 ? "default" : "pointer", fontFamily: "inherit"
          }}>Next →</button>
      </div>
    </div>
  );
}

export default function App() {
  const [activeSubject, setActiveSubject] = useState(() => {
    const saved = localStorage.getItem("quiz_active_subject");
    return (saved && SUBJECTS[saved]) ? saved : "cn";
  });

  useEffect(() => {
    localStorage.setItem("quiz_active_subject", activeSubject);
  }, [activeSubject]);

  const S = SUBJECTS[activeSubject];

  return (
    <>
      <style>
        {`
        @keyframes pop {
          0% { transform: scale(0.8); }
          50% { transform: scale(1.15); }
          100% { transform: scale(1); }
        }
        .pop-anim {
          animation: pop 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) both;
        }
        button:focus { outline: none; }
        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }
      `}
      </style>
      <div style={{
        minHeight: "100vh",
        background: S.gradient,
        transition: "background 0.5s ease",
        padding: "0 0 40px"
      }}>
        {/* ── TOP HEADER ── */}
        <div style={{
          background: S.headerBg,
          borderBottom: `1px solid ${S.accent}30`,
          padding: "20px 20px 0",
          transition: "background 0.5s ease"
        }}>
          <div style={{ maxWidth: 840, margin: "0 auto" }}>
            {/* Title row */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12, marginBottom: 18 }}>
              <div>
                <div style={{ fontSize: 11, color: "#475569", letterSpacing: "3px", textTransform: "uppercase", marginBottom: 5 }}>
                  MNC Placement Prep · All-in-One Quiz
                </div>
                <div style={{ fontSize: 28, fontWeight: 800, color: "#f1f5f9", letterSpacing: "-0.5px", lineHeight: 1.1 }}>
                  {S.emoji} {S.name}{" "}
                  <span style={{ color: S.accent, fontSize: 22 }}>Mastery</span>
                </div>
                <div style={{ fontSize: 13, color: "#64748b", marginTop: 5 }}>
                  {S.questions.length} questions · Foundational → Advanced → Scenario
                </div>
              </div>
              {/* subject stats */}
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                {Object.entries(S.diffColors).map(([k, v]) => (
                  <div key={k} style={{
                    background: "rgba(255,255,255,0.05)",
                    border: `1px solid ${v.color}25`, borderRadius: 10, padding: "7px 12px", textAlign: "center"
                  }}>
                    <div style={{ fontSize: 17, fontWeight: 800, color: v.color, lineHeight: 1 }}>
                      {S.questions.filter(q => q.diff === k).length}
                    </div>
                    <div style={{ fontSize: 10, color: "#64748b", marginTop: 2, letterSpacing: "0.4px" }}>{v.label}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Subject switcher tabs */}
            <div style={{ display: "flex", gap: 0, borderTop: "1px solid rgba(255,255,255,0.06)" }}>
              {Object.values(SUBJECTS).map(sub => (
                <button key={sub.key} onClick={() => setActiveSubject(sub.key)} style={{
                  padding: "13px 28px", fontSize: 14, fontWeight: activeSubject === sub.key ? 700 : 400,
                  background: "transparent",
                  color: activeSubject === sub.key ? sub.accent : "#475569",
                  border: "none", borderBottom: activeSubject === sub.key ? `2.5px solid ${sub.accent}` : "2.5px solid transparent",
                  cursor: "pointer", fontFamily: "inherit", transition: "all 0.2s",
                  letterSpacing: "0.3px"
                }}>
                  {sub.emoji} {sub.name}
                  <span style={{ marginLeft: 8, fontSize: 11, opacity: 0.7 }}>({sub.questions.length})</span>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* ── QUIZ PANEL ── */}
        <div style={{ maxWidth: 840, margin: "0 auto", padding: "20px 16px 0" }}>
          <QuizPanel key={activeSubject} subjectKey={activeSubject} />
        </div>
      </div>
    </>
  );
}
